INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'beijing_kunqu_culture',
  'beijing',
  'Beijing Opera Experience Guide: Jingju and Kunqu',
  '北京京昆文化体验推荐指南',
  'Jingju (Beijing Opera) and Kunqu are the two most iconic forms of traditional Chinese opera.',
  '🎭',
  'Culture',
  ARRAY[]::TEXT[],
  '<h2>Part One: Jingju (Beijing Opera)</h2><h3>1. Liyuan Theatre</h3><p>Beijing''s first teahouse-style Jingju theatre, located on the ground floor of the Qianmen Jianguo Hotel in Xicheng District. Performances have run every evening since 1990 — every night except Chinese New Year''s Eve — and feature classic excerpts including "Farewell My Concubine," "The Crossroads," and "Heavenly Maiden Scatters Flowers." Audience members sit around traditional Eight Immortals tables, sipping covered-bowl tea and sampling Beijing snacks while watching performers up close. Heads of state from dozens of countries have attended here, making it the top choice for international visitors new to Jingju.</p><ul><li><strong>Address:</strong> Ground floor, Qianmen Jianguo Hotel, 175 Yong''an Road, Xicheng District, Beijing</li><li><strong>Performance time:</strong> Every evening, 19:30–20:30 (doors open 30 minutes early — arrive to watch the performers apply their makeup)</li><li><strong>Ticketing hours:</strong> Day of performance, 13:00–21:30</li><li><strong>Booking:</strong> Official website www.liyuanjuchang.com | Hotline 400-0829-115</li></ul><h3>2. Mei Lanfang Grand Theatre</h3><p>Home of the National Peking Opera Company, this grand modern venue seats 1,028 and is named after the legendary Jingju master Mei Lanfang. The lobby is dominated by a striking eight-meter-tall statue of the warrior deity Guan Yu. Regular productions include full-length classics such as "The Dragon and Phoenix Present Blessings," "The Locked Brocade Pouch," and "Si Lang Visits His Mother," alongside excerpt showcases. State-of-the-art lighting and sound make this the venue of choice for visitors who want a high-production-value experience.</p><ul><li><strong>Address:</strong> 32 Ping''anli West Street, Xicheng District (about 160 meters from the southeast exit of Chegongzhuang subway station)</li><li><strong>Ticketing hours:</strong> Daily 09:30–20:00</li><li><strong>Booking:</strong> Official website www.bjmlfdjy.cn | Tel 010-58331388</li></ul><h3>3. Chang''an Grand Theatre</h3><p>Founded in 1937 and now housed inside the Guanghua Chang''an Building on East Chang''an Avenue. The theatre blends Ming-Qing classical aesthetics with modern technology — rosewood paneling and rich ornamentation make it a cultural landmark on this historic boulevard. Programming centers on Jingju but also includes Kunqu and other traditional opera forms. A full range of classic full-length productions and excerpt evenings runs year-round, making it an ideal first stop for visitors new to Chinese opera.</p><ul><li><strong>Address:</strong> 7 Jianguomen Inner Street, Dongcheng District (inside the Guanghua Chang''an Building)</li><li><strong>Ticketing hours:</strong> Daily 09:00–19:30</li><li><strong>Booking:</strong> Official website www.changandaxiyuan.cn | Hotline 010-65526852</li></ul><h3>4. Huguang Guild Hall</h3><p>A historic opera stage with over 200 years of history, managed by the Beijing Opera Museum. The museum traces the full arc of Jingju''s development and displays precious artifacts including costumes, headdresses, and folding fans once owned by legendary performers. Regular programming includes Jingju classics and an immersive musical, "Gold Wind and Jade Dew," which follows the audience through the guild hall''s many historic rooms and into the drama itself. A heritage workshop lets you try painting face masks or dressing in full stage costume.</p><ul><li><strong>Address:</strong> 3 Hufang Road, Xicheng District (Exit D of Hufangqiao Station on Subway Line 7)</li><li><strong>Opening hours:</strong> Tuesday to Sunday, 09:00–22:00 (closed Mondays; special holidays may vary)</li><li><strong>Performance time:</strong> Daily 18:30–19:30 (advance tickets required)</li><li><strong>Booking:</strong> Official website huguangguildhallopera.com/booking | Search "Huguang Guild Hall" on Damai.cn</li></ul><h3>5. Laoshe Teahouse</h3><p>Named after the beloved Beijing novelist Lao She, this cultural teahouse combines dining, tea, and live performance under one roof. The signature variety show "Four Seasons Beijing · Tea" weaves together Jingju, Sichuan face-changing (Bian Lian), acrobatics, tea ceremony, and Chinese kung fu. A highlight is the long-spout copper-kettle tea pouring performance. The relaxed, festive atmosphere makes this an ideal one-stop introduction to Chinese traditional culture for international visitors.</p><ul><li><strong>Address:</strong> Building 3, Zhengyang Market, Qianmen West Street, Xicheng District (Exit C of Qianmen Station on Subway Line 2)</li><li><strong>Opening hours:</strong> Daily 10:00–22:00</li><li><strong>Evening show:</strong> Starts at 19:50 (doors open 10–15 minutes before showtime)</li><li><strong>Booking:</strong> Official website www.laosheteahouse.com | Search "Laoshe Teahouse" on Maoyan or Damai.cn</li></ul><h2>Part Two: Kunqu Opera</h2><h3>6. Zhengyi Ci Temple Stage</h3><p>A 300-year-old timber opera stage from the Qing dynasty, now operated by the Northern Kunqu Opera Theatre. The structure has been meticulously restored to its original form. The three-sided stage design places front-row audience members as close as three to four meters from the performers — every subtle expression is fully visible. Classic Kunqu productions including "The Peony Pavilion" and "The West Garden" run regularly. An experience area lets you try on costumes and learn basic movement; heritage workshops introduce filigree inlay and face mask painting.</p><ul><li><strong>Address:</strong> 220 Qianmen West River Bank Street, Xicheng District</li><li><strong>Performance time:</strong> Evening shows typically begin at 19:30 (check current schedule for specifics)</li><li><strong>Booking:</strong> Official website zycxl.goupiaotong.cn | Search "Zhengyi Ci Temple Stage" on Damai.cn</li></ul>',
  '[]'::jsonb,
  4,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
  city_id = EXCLUDED.city_id,
  title_en = EXCLUDED.title_en,
  title_zh = EXCLUDED.title_zh,
