INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'beijing_booking_tips',
  'beijing',
  'Beijing Booking and Queue Survival Guide for International Visitors',
  '北京景点预约与排队避坑指南',
  'This guide was written for you — the international visitor who has traveled a long way to be here.',
  '🎫',
  'Tips',
  ARRAY[]::TEXT[],
  '<p><strong>All information is current as of May 2026</strong>, including policy changes introduced in December 2025.</p><h2>Section 1: Why This Guide Exists</h2><p>China''s tourism booking system has undergone a fundamental transformation over the past three years:</p><p>1. <strong>Nearly every major attraction has switched from on-site ticket sales to real-name advance reservations and e-tickets</strong> 2. <strong>Chinese residents use national ID cards and WeChat mini-programs; international visitors use passports and different entry points</strong> 3. <strong>Multiple systems still require a Chinese phone number or a WeChat account</strong> 4. <strong>Tickets typically go on sale at 8:00 PM Beijing time, seven days before the visit date — and on peak dates they sell out within minutes</strong></p><p>The biggest challenge for international visitors is this: <strong>you don''t know what you don''t know.</strong> This guide surfaces every unwritten rule so you can sort out all your bookings before you even board the plane.</p><h2>Section 2: Difficulty Rankings by Attraction (S to C)</h2><h3>Red — Tier S (Hardest: Plan These First)</h3><p>#### 1. Palace Museum (Forbidden City)</p><h2>Difficulty: 5 out of 5</h2><ul><li><strong>Daily visitor cap:</strong> 40,000</li><li><strong>Tickets released:</strong> 7 days before your visit date, at <strong>8:00 PM Beijing time</strong></li><li><strong>How fast they sell out in peak season:</strong> During April–May, September–October, and holiday weekends, tickets are gone <strong>within minutes</strong></li><li><strong>Closed:</strong> Every Monday (except public holidays)</li><li><strong>Advance reservation required:</strong> Yes, mandatory — only through the official website; <strong>no on-site sales</strong></li></ul><p><strong>Why Tier S:</strong> Strict capacity limits, enormous popularity, and a website that — despite having an English interface — still has pitfalls for international users.</p><p>#### 2. Tian''anmen Square</p><h2>Difficulty: 5 out of 5</h2><ul><li><strong>Tickets:</strong> <strong>Free</strong>, but real-name advance reservation is compulsory</li><li><strong>Opening hours:</strong> Approximately 60 minutes before sunrise to 60 minutes after sunset</li><li><strong>Daily visitor cap:</strong> Yes; fills up quickly in peak season</li><li><strong>Official booking channel:</strong> WeChat mini-program "Tian''anmen Square Reservation" (interface is entirely in Chinese)</li><li><strong>Advance booking window:</strong> 7 days before your visit</li></ul><p><strong>Why Tier S:</strong> Since December 15, 2021, <strong>all visitors — including international travelers, tour groups, and families — are turned away at the gate without a reservation.</strong> The hardest part for international visitors is that the reservation system <strong>has no English version</strong>, and some foreign phone numbers fail to receive verification texts.</p><h3>Yellow — Tier A (Difficult: Book at Least 3 Days Ahead)</h3><p>#### 3. National Museum of China</p><h2>Difficulty: 4 out of 5</h2><ul><li><strong>Tickets:</strong> <strong>Free</strong>, but real-name reservation required</li><li><strong>Location:</strong> East side of Tian''anmen Square</li><li><strong>Closed:</strong> Every Monday</li><li><strong>Advance booking window:</strong> 7 days before your visit</li><li><strong>Booking channel:</strong> Official WeChat mini-program "National Museum" (search in Chinese)</li></ul><p><strong>Insider tip:</strong> If you have already reserved a spot at the National Museum, <strong>you can use that reservation code plus your passport to enter Tian''anmen Square on the same day — without a separate square reservation.</strong> This is the most useful workaround for international visitors.</p><p>#### 4. Mutianyu Great Wall</p><h2>Difficulty: 3 out of 5</h2><ul><li><strong>Tickets:</strong> 45 yuan adults (peak season) / 40 yuan (off-peak)</li><li><strong>Advance booking window:</strong> 15 days before your visit (some platforms allow up to 30 days)</li><li><strong>Daily visitor cap:</strong> Exists but is generous; weekday same-day booking is usually fine</li><li><strong>Official channel:</strong> <strong>en.mutianyugreatwall.com</strong> (full English interface)</li><li><strong>International visitor convenience:</strong> Mutianyu has partnered with Visa to create a "Visa International Friendly Payment Zone" — the first at a UNESCO World Heritage site in China — meaning you can pay directly with a foreign credit card, no need to set up Alipay in advance</li></ul><h3>Why not Tier S:<strong> The English website is user-friendly, capacity limits are relaxed, and on-site tickets are available. Still, booking ahead is wise — </strong>weekends and public holidays can sell out.</h3><h3>Blue — Tier B (Moderate: Same-Day or Next-Day Booking Usually Works)</h3><p>#### 5. Temple of Heaven</p><ul><li><strong>Combined ticket:</strong> 34 yuan (peak season) / 28 yuan (off-peak) — includes the Hall of Prayer for Good Harvests, Echo Wall, and Circular Mound Altar</li><li><strong>Park-only ticket:</strong> 15 yuan (excludes the three main structures)</li><li><strong>Reservation:</strong> Online real-name reservation required, but tickets <strong>are almost always available on the day</strong></li><li><strong>Booking:</strong> WeChat mini-program "Temple of Heaven Park" or Trip.com</li><li><strong>Closed:</strong> Never</li></ul><p><strong>Tip for international visitors:</strong> Coming in through the park entrance between 6:00 AM and 8:00 AM to watch locals doing morning exercises <strong>does not require the full combined ticket</strong> — the 15-yuan park ticket is enough, and that early hour is when the atmosphere is most magical.</p><p>#### 6. Summer Palace</p><ul><li><strong>Combined ticket:</strong> 50 yuan (peak) / 40 yuan (off-peak)</li><li><strong>Reservation:</strong> Real-name reservation required, but <strong>tickets are usually available on the day</strong></li><li><strong>Closed:</strong> Never</li><li><strong>Booking:</strong> WeChat mini-program "Summer Palace" or Trip.com</li></ul><p>#### 7. Yonghe Lama Temple</p><ul><li><strong>Ticket:</strong> 25 yuan (includes incense)</li><li><strong>Reservation:</strong> Online reservation required; <strong>capacity is almost never reached</strong></li><li><strong>Special note:</strong> On the first and fifteenth days of the lunar calendar (Buddhist holy days), the temple is packed with worshippers — worth avoiding on those dates</li></ul><h3>Green — Tier C (Easiest: Just Walk In)</h3><p>| Attraction | Ticket | Reservation | Notes | |---|---|---|---| | <strong>Jingshan Park</strong> | 2 yuan | Not required | Buy at the gate; best panoramic view of the Forbidden City | | <strong>798 Art District</strong> | Free | Not required | Tickets may be needed for individual gallery shows | | <strong>Nanluoguxiang / Shichahai</strong> | Free | Not required | Walking areas, open any time | | <strong>Beihai Park</strong> | 10 yuan | Not required | Buy on-site | | <strong>Imperial College and Confucius Temple</strong> | 30 yuan combined | Not required | Buy on-site | | <strong>Fayuan Temple</strong> | 5 yuan | Not required | Tang-dynasty temple near Niujie | | <strong>Shougang Park</strong> | Free | Some venues require tickets | Main outdoor spaces are open access |</p><h2>Section 3: Step-by-Step Booking Instructions (Seven Key Attractions)</h2><h3>Red — Attraction 1: Palace Museum — Full Booking Walkthrough</h3><p>#### Step 1: Prepare (10 days before departure)</p><ul><li>✅ Your <strong>original passport</strong> — must be the same one you will use in Beijing</li><li>✅ An <strong>email address</strong> (set up Gmail access before leaving your home country; Gmail may be unreliable inside China — Outlook, ProtonMail, Yahoo, or your local provider all work)</li><li>✅ A <strong>foreign credit card</strong> (Visa, Mastercard, or Amex) or Alipay International linked to a foreign card</li><li>✅ A <strong>stable internet connection</strong> (VPNs inside China can be unreliable — complete your booking before you arrive)</li></ul><p>#### Step 2: Go to the Official Website Visit <strong>https://en.dpm.org.cn</strong> (the Palace Museum''s official English website).</p><p>#### Step 3: Create an Account</p><ul><li>Click <strong>"Sign In"</strong> in the top-right corner</li><li>Enter your email address and receive a verification code (valid for 5 minutes)</li><li>No Chinese phone number required</li></ul><p>#### Step 4: Choose a Date and Session</p><ul><li>The system <strong>only releases tickets for dates 7 days out</strong>: for example, after 8:00 PM Beijing time on June 1, you can book June 8</li><li>Select <strong>"Adult Ticket"</strong> (60 yuan peak season / 40 yuan off-peak)</li><li>Strongly recommended add-ons:</li><li><strong>Treasure Gallery — 10 yuan</strong></li><li><strong>Clock Gallery — 10 yuan</strong></li><li>Choose a morning or afternoon session</li></ul><p>#### Step 5: Enter Visitor Information Each ticket requires the <strong>actual visitor''s</strong>:</p><ul><li>Full name (exactly as it appears on the passport, including middle names)</li><li>Passport number</li><li>Nationality</li></ul><p>#### Step 6: Pay</p><ul><li>Payment options: foreign credit card or Alipay International</li><li>After payment, your <strong>e-ticket will arrive by email</strong></li></ul><p>#### Step 7: On the Day</p><ul><li>Enter through the <strong>Meridian Gate (South Gate)</strong></li><li>Two queues: the left lane is for Chinese ID cards; <strong>the right lane is for foreign passports</strong></li><li>Show the <strong>same passport used for the booking</strong></li><li>Staff scan your passport; the system pulls up your reservation automatically</li><li>Pass security — welcome to the Forbidden City</li></ul><p>#### If Tickets Are Sold Out — Backup Options 1. <strong>Refresh between 8:00 and 9:00 PM</strong> — unpaid reservations are returned to the pool 2. <strong>Third-party agents:</strong> Trip.com, Klook, or Viator (service fees of 50–150 yuan, but they handle the hard work) 3. <strong>Official paid guide tours:</strong> Include the ticket, but are expensive (800 yuan or more per person) 4. <strong>Shift your date:</strong> Tuesday, Wednesday, and Thursday are far less competitive than weekends</p><h3>Red — Attraction 2: Tian''anmen Square — The Biggest Trap for International Visitors</h3><p>#### The Reality</p><ul><li>The official booking system is a <strong>WeChat mini-program called "Tian''anmen Square Reservation"</strong></li><li>That mini-program <strong>is entirely in Chinese</strong></li><li>Foreign phone numbers may fail at the verification step</li></ul><p>#### Three Solutions</p><h2>Option A (Most Recommended): Piggyback Entry</h2><p>If you have already booked the <strong>Forbidden City</strong> or the <strong>National Museum</strong> on the same day, you can enter Tian''anmen Square with that reservation code and your passport — <strong>no separate square reservation needed.</strong> This is the most efficient path.</p><h2>Option B (Self-booking through WeChat)</h2><p>1. Download <strong>WeChat</strong> (do this before leaving home; registering inside China is more complicated) 2. Register with a foreign phone number (some countries may need a local user to help "scan-activate" your account — the hotel concierge can usually assist) 3. Search for the <strong>"Tian''anmen Square Reservation"</strong> mini-program inside WeChat 4. Use Google Translate in camera mode to translate the interface in real time 5. Look for the <strong>"Foreign Visitor Reservation"</strong> entry point 6. Fill in your passport details 7. Choose a time slot: flag raising / morning / afternoon / flag lowering</p><h2>Option C (Easiest): Use a Booking Agent</h2><ul><li><strong>Viator, Klook, GetYourGuide, and Trip.com</strong> all offer Tian''anmen Square reservation assistance</li><li>Cost: typically 50–100 yuan per person</li><li>Process: fill in passport details → receive email confirmation → scan code at the entrance</li></ul><p>#### On the Day</p><ul><li>Entering from the <strong>south (Qianmen side)</strong> is smoother than the north entrance</li><li><strong>Bring your original passport</strong> — photos on a phone are not accepted</li><li>Three security checks: identity verification → X-ray for bags → body search</li><li><strong>Do not bring:</strong> lighters, knives, selfie sticks (restricted in some situations), or drones</li><li>Expect queues of 30–60 minutes in peak season</li></ul><p>#### Flag-Raising and Lowering Schedule</p><ul><li>Flag raising: timed to local sunrise (as early as 4:46 AM at summer solstice, as late as 7:36 AM at winter solstice)</li><li>Flag lowering: timed to local sunset</li><li>To watch the flag raising, you must select the dedicated "flag raising" time slot (which means entering in the early hours of the morning)</li></ul><h3>Yellow — Attraction 3: National Museum of China</h3><p>#### Booking Difficulty</p><ul><li>Free but <strong>in high demand</strong> — in peak season, book one to two weeks ahead</li><li>Weekends and public holidays often <strong>fill within a few hours</strong></li></ul><p>#### Step-by-Step 1. Search for the <strong>"National Museum"</strong> mini-program in WeChat (blue logo) 2. During registration, select <strong>"Passport"</strong> as your ID type 3. Enter your name exactly as it appears on your passport 4. Choose a time slot (five slots available each day) 5. Confirmation arrives immediately and is also viewable inside WeChat</p><p>#### On the Day</p><ul><li>Enter through the <strong>north entrance</strong> (facing Tian''anmen Square)</li><li>Show your original passport (the system scans it against your reservation)</li><li>Once inside, <strong>allow at least 3 hours</strong> — this is one of the world''s largest museums, with 1.43 million artifacts in its collection</li></ul><p>#### Alternative: Book Through Trip.com</p><ul><li>Some booking agents <strong>do not accept mainland Chinese passports</strong> — these services are designed specifically for international visitors</li><li>Service fee: 40–80 yuan per person</li><li>Up to 5 visitors can be booked at once</li></ul><h3>Yellow — Attraction 4: Mutianyu Great Wall</h3><p>#### Good News Mutianyu is the <strong>most international-visitor-friendly</strong> of all the attractions that require advance booking.</p><p>#### Three Ways to Buy Tickets</p><h2>Option 1 (Recommended): Official English Website</h2><ul><li>Visit <strong>en.mutianyugreatwall.com</strong></li><li>Choose your date</li><li>Select ticket type:</li><li>Basic admission (45 yuan)</li><li>Admission plus shuttle bus (60 yuan)</li><li>Admission plus one-way cable car (from 120 yuan)</li><li>Admission plus cable car up and toboggan slide down (200 yuan) — <strong>highly recommended for families</strong></li><li>Enter your passport number</li><li>Visa and Mastercard accepted directly ("Visa International Friendly Payment Zone")</li><li>Receive an email with a QR code attached</li></ul><h2>Option 2: Trip.com</h2><ul><li>Full English interface, transparent pricing</li><li>Can book round-trip private car transfers at the same time (approximately 400–600 yuan per car for four people)</li></ul><h2>Option 3: On-Site Same Day</h2><ul><li>The ticket window accepts passports</li><li>Arrive at least one hour early; popular time slots may be capped</li></ul><p>#### Suggested Route on the Day Cable car up → Watchtower 14 → walk to Watchtower 20 (the most scenic stretch) → walk back to Watchtower 14 → toboggan slide down Total time: approximately 3 hours</p><p>#### Key Hours</p><ul><li>Peak season (March 16–November 15): cable car 7:30–17:30</li><li>Off-peak season: cable car 8:00–17:00</li></ul><h3>Blue — Attractions 5, 6, and 7: Temple of Heaven, Summer Palace, Yonghe Lama Temple</h3><p>These three attractions follow a similar pattern:</p><p>#### What They Have in Common</p><ul><li>Online real-name reservation required</li><li><strong>Day-of tickets are almost always available</strong></li><li>Scan code on arrival</li></ul><p>#### Easiest Booking Method</p><h2>Recommended order for international visitors:</h2><p>1. <strong>Trip.com</strong> — full English, no Chinese phone number needed, buy tickets for multiple attractions in one session 2. <strong>On-site scanning machines at the entrance</strong> — some support passport real-name verification (look for English signage) 3. <strong>WeChat mini-programs</strong> — require a Chinese phone number to register; least convenient option</p><p>#### Key Points by Attraction</p><h2>Temple of Heaven</h2><ul><li>Combined ticket: 34 yuan peak / 28 yuan off-peak</li><li>Park-only ticket (15 yuan) is enough to watch morning exercises — no entry to the Hall of Prayer for Good Harvests required</li><li>Recommended entrance: <strong>South Gate</strong> (near the Circular Mound Altar — working through the complex in reverse order of the imperial procession creates a more dramatic experience)</li></ul><h2>Summer Palace</h2><ul><li>Combined ticket: 50 yuan peak / 40 yuan off-peak</li><li>Recommended route: <strong>enter through East Palace Gate, exit through North Palace Gate</strong> (follows the natural terrain, less tiring)</li><li>Allow at least 3–4 hours</li></ul><h2>Yonghe Lama Temple</h2><ul><li>25 yuan, includes incense</li><li>A 5-minute walk takes you to the Imperial College and Confucius Temple</li><li>Avoid the first and fifteenth days of the lunar calendar</li></ul><h2>Section 4: Attractions That Need No Reservation (Take a Deep Breath)</h2><p>You can <strong>walk straight into</strong> all of these with no advance planning:</p><p>| Attraction | Ticket | How to Pay | |---|---|---| | Jingshan Park | 2 yuan | Cash or scan to pay at the gate | | 798 Art District | Free | Walk in | | Nanluoguxiang | Free | Pedestrian street | | Shichahai / Houhai | Free | Walking is free; boat rental charged separately | | Beihai Park | 10 yuan | Buy on-site | | Imperial College and Confucius Temple | 30 yuan | Buy on-site | | Fayuan Temple | 5 yuan | Buy on-site | | Dashilar / Qianmen Street | Free | Pedestrian street | | Wudaoying Hutong | Free | Pedestrian street | | Drum Tower and Bell Tower | 30 yuan combined | Buy on-site |</p><h2>Section 5: Your Planning Timeline — Countdown to Beijing</h2><h3>14 Days Before Departure (Start Here)</h3><ul><li>[ ] Download <strong>Alipay</strong> International and link a foreign credit card (or activate the <strong>Alipay Tour Pass</strong>)</li><li>[ ] Download <strong>WeChat</strong> and register with your foreign phone number (ask hotel staff to help activate if needed)</li><li>[ ] Download the <strong>Trip.com</strong> app</li><li>[ ] Download <strong>DiDi</strong> (China''s ride-hailing app, available in English)</li><li>[ ] Arrange an <strong>eSIM or international roaming SIM</strong> (Google, Instagram, Facebook, WhatsApp, and YouTube are inaccessible on the Chinese mainland)</li><li>[ ] Download <strong>Google Translate''s offline Chinese language pack</strong> and a backup copy of Microsoft Translator</li><li>[ ] Save a color scan of your passport on your phone</li></ul><h3>7–10 Days Before Departure — Most Important</h3><ul><li>[ ] <strong>Grab Forbidden City tickets:</strong> Refresh en.dpm.org.cn at exactly 8:00 PM Beijing time</li><li>[ ] Book Mutianyu Great Wall tickets at the same time (available up to 15 days ahead)</li><li>[ ] Reserve the National Museum at the same time</li><li>[ ] Book Tian''anmen Square through a third-party agent (or combine with your Forbidden City or National Museum day)</li></ul><h3>3–5 Days Before Departure</h3><ul><li>[ ] Book restaurants: for popular spots like Siji Minfu and Jubaoyuan, use Dianping to join the waitlist in advance</li><li>[ ] Michelin restaurants: book through OpenTable or ask your hotel concierge</li><li>[ ] Confirm the exact entrance location of each attraction (use Apple Maps or Amap)</li></ul><h3>The Day Before</h3><ul><li>[ ] Screenshot all reservation QR codes and save to your camera roll (<strong>don''t rely on email alone — it may not load if the connection is unstable</strong>)</li><li>[ ] Charge all cameras and phones</li><li>[ ] Print a backup booking summary (your hotel can print it — useful if electronics fail)</li></ul><h3>Day Of</h3><ul><li>[ ] <strong>Bring your original passport to every attraction</strong> (not a photocopy, not a phone photo)</li><li>[ ] Head out early (the first hour after opening has the fewest crowds)</li><li>[ ] Leave behind: lighters, knives, selfie sticks (restricted at some sites), and drones</li></ul><h2>Section 6: Key Phrases in Pinyin (Emergency Use)</h2><p>If the system freezes and staff only speak Chinese, these phrases may help — show them on screen or read them aloud:</p><p>| Pinyin | English | |--------|---------| | Wǒ shì wàiguó rén, xūyào bāngzhù | I''m a foreigner, I need help | | Wǒ yǐjīng yùyuē le | I have a reservation | | Zhè shì wǒ de hùzhào | This is my passport | | Qǐng bāng wǒ sǎomiáo | Please help me scan | | Wǒ de piào zài nǎlǐ | Where is my ticket | | Wǒ bú huì shuō zhōngwén | I don''t speak Chinese | | Zhèlǐ yǒu yīngwén ma | Is there English here | | Xièxiè | Thank you |</p><h2>Section 7: Emergency Contacts</h2><p>If you run into difficulties with reservations or entry:</p><p>| Service | Phone | Language | |---------|-------|----------| | Beijing Tourism Hotline | <strong>12301</strong> | Chinese / English | | General Services Hotline | <strong>12345</strong> | Chinese / English | | Police | <strong>110</strong> | Chinese (say "English please" to be transferred) | | International Hospital (Beijing United Family Hospital) | <strong>+86 10 5927 7000</strong> | English | | Forbidden City Inquiry Hotline | <strong>+86 400 950 1925</strong> | Chinese (limited English) | | Mutianyu Great Wall English Hotline | <strong>010-69121880</strong> (daily 8:00–17:00) | English |</p><h2>Section 8: Restaurant Queue Strategy</h2><p>Once you''ve sorted out the attractions, there''s still the "queue battle" for food. At Beijing''s most popular old-school restaurants, peak-hour waits of one to two hours are perfectly normal.</p><h3>Strategy 1: Use Dianping to Join the Remote Queue</h3><ul><li>Dianping is China''s Yelp — you can use the app to <strong>join the queue hours in advance</strong> (you get a queue number without being physically at the restaurant)</li><li>This is what every young Beijinger does</li><li>The app is available in English (search "Dianping")</li></ul><h3>Strategy 2: Eat at Off-Peak Times</h3><ul><li>Beijing restaurant peaks: <strong>12:00–13:00 (lunch) and 18:30–20:00 (dinner)</strong></li><li>Arrive outside those windows and you''ll almost never queue</li><li>Try 11:00 for lunch and 17:30 for dinner</li></ul><h3>Strategy 3: Which Restaurants Require Advance Booking</h3><ul><li><strong>Michelin-starred restaurants:</strong> All of them — book one to two weeks ahead</li><li><strong>Xin Rong Ji / Chao Shang Chao:</strong> Weekend reservations fill up two weeks in advance</li><li><strong>King''s Joy (Jingzhaoyin):</strong> Book three to five days ahead</li><li><strong>Dadong (Tuanjiehucun branch):</strong> Book one week ahead</li><li><strong>Popular Beijing cuisine spots:</strong> No reservation needed but try off-peak hours</li></ul><h3>Strategy 4: When You See a Two-Hour Queue at the Door</h3><ul><li><strong>Siji Minfu (Forbidden City branch):</strong> Waits often exceed 90 minutes — consider going to the Wangfujing or Workers'' Stadium branch instead</li><li><strong>Jubaoyuan (Niujie):</strong> Always a queue — try one of the neighboring Halal hotpot restaurants on the same street, like Hongji</li><li><strong>Huda Restaurant:</strong> The Guijie strip has several other crayfish spots nearby with similar flavors</li></ul><h2>Section 9: A Few Words Before You Go</h2><p>When writing this guide, we kept picturing the same scene: you arriving at Beijing Capital International Airport with your suitcase, your Chinese SIM just activated and still unfamiliar, staring at a screen of Chinese booking interfaces with no idea where to start.</p><p>Please remember: 1. <strong>Slow down.</strong> Beijing has 3,000 years of history. Seeing one fewer attraction does not matter. <strong>What matters is how you will remember this city when you get home.</strong> 2. <strong>Using Trip.com beats struggling with WeChat.</strong> Paying a small service fee for peace of mind is worth it. 3. <strong>Your hotel concierge is your friend.</strong> Any mid-range or above hotel in Beijing will have staff who can communicate in English and can help with ticket bookings, restaurant reservations, and rides. 4. <strong>Don''t panic if you''re turned away.</strong> If one attraction''s booking system doesn''t work for you, there is almost certainly a third-party solution. 5. <strong>WeChat is not essential.</strong> If you''d rather not download it, <strong>you can handle almost everything with Trip.com, cash, a credit card, and your passport.</strong></p><p>Beijing welcomes you. The city''s real magic is not at the attractions that require four-hour queues — it''s at a breakfast stall in a hutong in the early morning, at the moment you see those golden rooftops from the top of Jingshan Park, at the instant a pedicab driver tries to tell you old Beijing stories in broken English.</p><p>May this city be gentle with you.</p><p>This is a guide that will keep evolving. Booking policies at Chinese attractions change frequently — please reconfirm key details (especially the Forbidden City reservation window and the Tian''anmen mini-program entry point) immediately before your trip. We wish every scan, every passport check, and every entry gate in Beijing a smooth and easy experience.</p><p>— Written for every international traveler brave enough to explore China</p>',
  '[]'::jsonb,
  5,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
  city_id = EXCLUDED.city_id,
  title_en = EXCLUDED.title_en,
  title_zh = EXCLUDED.title_zh,
  subtitle = EXCLUDED.subtitle,
  icon = EXCLUDED.icon,
  badge = EXCLUDED.badge,
  cover_images = EXCLUDED.cover_images,
  body = EXCLUDED.body,
  meta_items = EXCLUDED.meta_items,
  audio_url = NULL,
  audio_title = NULL,
  audio_duration_seconds = 0,
  audio_quote = NULL,
  audio_transcript = NULL,
  display_order = EXCLUDED.display_order,
  is_published = EXCLUDED.is_published,
  updated_at = NOW();

INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'beijing_food_suipo',
  'beijing',
  'Beijing Food Guide',
  '北京美食推荐指南',
  'This guide is based on restaurant reviews by Sui Po (Te Chu Sui Po), a certified master chef and food blogger.',
  '🍜',
  'Food',
  ARRAY[]::TEXT[],
  '<h2>Recommended by Sui Po</h2><h2>About Sui Po</h2><p>Sui Po, also known online as "Te Chu Sui Po," is a certified master chef based in Beijing. He previously served as executive chef at Hilton and InterContinental hotels, and trained under master chef Zheng Xiusheng, who prepared state banquets. His restaurant review videos are known for professional and unbiased food critiques, and he has nearly 10 million followers across Chinese social media platforms.</p><h2>Restaurant Recommendations</h2><h3>1. Shui Yi Fang Fish Restaurant</h3><p><strong>Cuisine:</strong> Northeast Chinese</p><p><strong>Address:</strong> Near Dixingju, Ande Road, Dongcheng District, Beijing</p><h2>Why We Recommend It:</h2><p>This is a hidden family-run Northeast Chinese restaurant tucked deep in a hutong alley — it doesn''t even have a proper front entrance. Navigation apps only lead you to a street-facing window. The restaurant is run by a trained female chef who serves authentic, hearty Northeast dishes with genuine ingredients. Sui Po gave it a rare "all positive" review, praising the kitchen for cooking "with sincerity."</p><h2>Signature Dishes:</h2><ul><li>Pickled Cabbage with Pork Belly</li><li>Songjiang Fish, Northeast Style</li><li>Home-style Fried Pork Cubes</li></ul><p><strong>Average Cost:</strong> Approximately 97 RMB per person</p><h3>2. Liu Lin Roast Duck Restaurant</h3><p><strong>Cuisine:</strong> Beijing Cuisine — Roast Duck</p><p><strong>Address:</strong> 15A Fuxing Road, Haidian District, Beijing</p><h2>Why We Recommend It:</h2><p>This is a decades-old affordable roast duck restaurant offering authentic Beijing duck at reasonable prices — a high-value option for experiencing genuine Peking duck. Sui Po made a dedicated video recommending it, praising the consistent quality and accessible pricing, making it a great choice for everyday diners.</p><h2>Signature Dishes:</h2><ul><li>Beijing Roast Duck</li><li>Home-style Dishes</li></ul><p><strong>Average Cost:</strong> Budget-friendly</p><h3>3. San Yang Cai</h3><p><strong>Cuisine:</strong> Chongqing Jianghu Cuisine (Sichuan-style)</p><p><strong>Address:</strong> Inside the North Gate of Workers'' Stadium, Chaoyang District, Beijing</p><h2>Why We Recommend It:</h2><p>San Yang Cai is a representative restaurant for Beijing''s jianghu cuisine — the bold, rustic dishes associated with the "rivers and lakes" of Chinese popular culture. Located in the trendy Workers'' Stadium area, it covers 2,700 square metres and seats more than 400 guests. The red-themed decor suits various banquet occasions. Sui Po featured it in his "memory series," calling the jianghu dishes authentic and distinctive.</p><h2>Signature Dishes:</h2><ul><li>Jianghu Cuisine Series</li><li>Chongqing-style Specialties</li></ul><p><strong>Average Cost:</strong> Good value for money</p><h3>4. Chu Yi Xiao Hu Nan</h3><p><strong>Cuisine:</strong> Hunan Cuisine</p><h2>Why We Recommend It:</h2><p>This husband-and-wife Hunan restaurant received a strong recommendation from Sui Po on Douyin in November 2025. Dishes to try include cumin lamb, dry-pot potatoes, and the three-ingredient Hunan hot pot. The video went viral and caused wait times of over 1.5 hours. Everything is wok-fried to order with intense heat. Online reviewers have called it "the ceiling of canteen-level food."</p><h2>Signature Dishes:</h2><ul><li>Cumin Lamb</li><li>Dry-pot Potatoes</li><li>Three-ingredient Hunan Hot Pot</li><li>"Bandit" Pig Liver</li></ul><p><strong>Note:</strong> Expect long waits. Consider visiting during off-peak hours.</p><h3>5. Zhi Mei Lou</h3><p><strong>Cuisine:</strong> Shandong Cuisine (one of Beijing''s historic Eight Great Restaurants)</p><p><strong>Address:</strong> Beijing (please check for the current address before visiting)</p><h2>Why We Recommend It:</h2><p>Zhi Mei Lou is one of Beijing''s historic "Eight Great Restaurants" — a time-honoured brand with a long history. After a recent visit, Sui Po recommended the signature spicy prawns and called them "great value." This is an excellent place to experience traditional Shandong cuisine and the culture of Beijing''s historic restaurant heritage.</p><h2>Signature Dishes:</h2><ul><li>Spicy Prawns</li><li>Classic Shandong Dishes</li></ul><p><strong>Features:</strong> Time-honoured brand, traditional Shandong cuisine</p><h3>6. Ji Jia Xiao Guan</h3><p><strong>Cuisine:</strong> Home-style Chinese Cuisine</p><p><strong>Address:</strong> Shop 16, Building 16, Yuhuayuan Erli East Gate, Daxing District, Beijing</p><h2>Why We Recommend It:</h2><p>This is a small restaurant where you can simply "eat comfortably" — a quality that prompted Sui Po to make a dedicated video about it. Located in Daxing District, it serves home-style dishes in a relaxed setting, ideal for casual dining. Sui Po''s assessment: restaurants like this "are truly hard to come by."</p><p><strong>Features:</strong> Comfortable dining experience, home-style flavours</p><h3>7. Jin Shan Xiao Guan</h3><p><strong>Cuisine:</strong> Sichuan Cuisine</p><h2>Why We Recommend It:</h2><p>This Sichuan restaurant is run by Sui Po''s apprentice. Sui Po featured it in a video showing how he teaches his student to cook. Dishes including spicy chicken, boiled fish in chilli oil, and stir-fried pig kidney are all showcased — aromatic and tempting. The spicy chicken is fried fresh to order: the meat stays moist with a light crunch, and the fragrance, heat, and numbing sensation all hit at once.</p><h2>Signature Dishes:</h2><ul><li>La Zi Ji (Spicy Chicken)</li><li>Boiled Fish in Hot Chilli Oil</li><li>Stir-fried Pig Kidney</li></ul><p><strong>Features:</strong> Master-apprentice heritage, authentic Sichuan flavours</p><h3>8. Mo Restaurant</h3><p><strong>Cuisine:</strong> Innovative Chinese Cuisine</p><p><strong>Recognition:</strong> Michelin One Star</p><h2>Why We Recommend It:</h2><p>Mo Restaurant is a Michelin-starred Beijing restaurant. Sui Po visited and reviewed the sweet and sour pork (119 RMB). As a certified master chef, Sui Po offered professional commentary on this classic dish''s preparation, concluding that the Michelin star is well-deserved. Recommended for visitors who want to experience refined Chinese cuisine at a high level.</p><h2>Signature Dishes:</h2><ul><li>Sweet and Sour Pork (119 RMB)</li></ul><p><strong>Average Cost:</strong> Higher-end</p><h2>Tips for Dining Out</h2><p>1. <strong>Reservations:</strong> Popular restaurants like Chu Yi Xiao Hu Nan and Mo Restaurant require advance reservations or a visit during off-peak hours.</p><p>2. <strong>Spiciness:</strong> Sichuan and Hunan dishes are spicy. If you can''t handle heat, let the staff know when you order.</p><p>3. <strong>Payment:</strong> Most restaurants accept WeChat Pay, Alipay, and cash.</p><p>4. <strong>Language:</strong> We recommend downloading a translation app or having your destination''s address written in Chinese before you go.</p><h2>Disclaimer</h2><p>This guide is compiled from Sui Po''s restaurant review videos and publicly available information. Restaurant details — including addresses, pricing, and opening hours — may change. Please verify the latest information through official channels before visiting.</p><p>*Last Updated: June 2026*</p>',
  '[]'::jsonb,
  6,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
  city_id = EXCLUDED.city_id,
  title_en = EXCLUDED.title_en,
  title_zh = EXCLUDED.title_zh,
  subtitle = EXCLUDED.subtitle,
  icon = EXCLUDED.icon,
  badge = EXCLUDED.badge,
  cover_images = EXCLUDED.cover_images,
  body = EXCLUDED.body,
  meta_items = EXCLUDED.meta_items,
  audio_url = NULL,
  audio_title = NULL,
  audio_duration_seconds = 0,
  audio_quote = NULL,
  audio_transcript = NULL,
  display_order = EXCLUDED.display_order,
  is_published = EXCLUDED.is_published,
