INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'hangzhou_coffee',
  'hangzhou',
  'Hangzhou Independent Specialty Coffee Guide · Top 10 for International Visitors',
  '杭州独立咖啡体验指南 · Top 10 for International Visitors',
  'This guide selects 10 of Hangzhou''s most representative independent coffee shops, covering specialty coffee, local culture, creative spaces, and more — a ready-to-use checklist for international visitors.',
  '☕',
  NULL,
  ARRAY[]::TEXT[],
  '<h2>1. Zidongwoxi Coffee — Gesha Specialty Shop</h2><ul><li><strong>Specialty:</strong> Opened in late 2016, one of the few specialty cafés in Hangzhou to roast its own beans. Now devoted entirely to Gesha coffee, with a lineup centered on Panama Gesha — including exclusive micro-lots and rare batches — ranging from light to medium-dark roasts.</li><li><strong>Signature drinks:</strong> Gesha pour-over (V60), medium-dark Gesha from Hacienda La Esmeralda</li><li><strong>Food:</strong> No set menu; focused entirely on coffee</li><li><strong>Address:</strong> Qingtai Street, Lucheng Yuanfuli, Shangcheng District (Wushan Square / Hefang Street area); second location at 45 Dajing Lane</li><li><strong>Why visit:</strong> A benchmark for specialty coffee in Hangzhou and a must for Gesha enthusiasts. The barista''s classic V60 technique brings out clear terroir character — every cup is a flavor masterclass.</li></ul><h2>2. Parking Coffee — China Champion Bar</h2><ul><li><strong>Specialty:</strong> Owner Pan Wei won the 2021 China Barista Championship and brings competition-level innovation to everyday service. The shop balances deep expertise with an approachable atmosphere, making it the most internationally recognized independent café in Hangzhou.</li><li><strong>Signature drinks:</strong> Champion Set (small Americano + small latte + signature special, three drinks in one), "Tennessee Tribute" creative cocktail coffee, natural-process Gesha latte</li><li><strong>Food:</strong> No set menu; focused entirely on coffee</li><li><strong>Address:</strong> 51 Hai''er Lane, Gongshu District; second location in Xiaoshan District</li><li><strong>Why visit:</strong> The flagship home of China''s top competitive barista achievement. The Champion Set lets you taste three different preparation styles in one sitting — the perfect bridge between professional technique and everyday drinking.</li></ul><h2>3. Ceremorning and Random Play — Mobile Art Gallery Café</h2><ul><li><strong>Specialty:</strong> A hybrid space blending coffee, house-roasted beans, pastries, organic brunch, and a curated art boutique. The ground floor serves drinks; the upper floor hosts artist exhibitions. Coffee and art flow naturally together. Set in the thousand-year-old Dajing Lane, it opens only three to four days a week.</li><li><strong>Signature drinks:</strong> House-roasted pour-over (Ethiopian Alo natural process, Panama Gesha), rice milk special (roasted grain aroma with orange peel freshness)</li><li><strong>Food:</strong> Creative pastries, light organic brunch</li><li><strong>Address:</strong> 6–10 Dajing Lane, Shangcheng District (at the foot of Wushan Hill, near Hefang Street)</li><li><strong>Why visit:</strong> Sip coffee while taking in a contemporary art exhibition — a microcosm of Hangzhou''s national lead in aesthetic sensibility. A modern lifestyle laboratory tucked inside an ancient alley.</li></ul><h2>4. Feiniao Ji — Japanese Garden Café on the West Lake Hillside</h2><ul><li><strong>Specialty:</strong> Set among the hills of Manjuelong in the West Lake Scenic Area and doubling as a guesthouse. Owner Cheng Wenbin is celebrated as Hangzhou''s foremost hand-brew specialist. The space leans toward Japanese styling, with generous natural wood that blends seamlessly into the forested hillside. Osmanthus trees grow in the courtyard — drinking a hand-brewed cup amid their autumn fragrance is an experience unique to Hangzhou.</li><li><strong>Signature drinks:</strong> Single-origin pour-over</li><li><strong>Food:</strong> Drinks and light meals (for both guesthouse guests and day visitors)</li><li><strong>Address:</strong> 1 Yangjiashan, Upper Manjuelong Village, Xihu District (near Leifeng Pagoda and Lingyin Temple)</li><li><strong>Why visit:</strong> The only space within the West Lake Scenic Area that combines guesthouse accommodation with specialty coffee. The pairing of autumn osmanthus and hand-brew coffee is a sensory memory unique to Hangzhou.</li></ul><h2>5. Shanye Café (BAC Zhuantang Branch) — Cave Coffee Reborn from an Industrial Ruin</h2><ul><li><strong>Specialty:</strong> Converted from the cylindrical silos of an abandoned cement factory, the space embraces a cave-like industrial aesthetic. Inside, the design wraps around the concrete silos; outside, a terrace opens onto a wide lawn. Longjing tea elements sit alongside industrial gears; the café serves coffee by day and cocktails by night, and has appeared as a filming location on a popular variety show.</li><li><strong>Signature drinks:</strong> Longjing tea fusion special (a creative blend of local Longjing tea and coffee)</li><li><strong>Food:</strong> Light meals</li><li><strong>Address:</strong> Building 7, Fenghuang Creative Park BAC, Xihu District (Zhuantang area)</li><li><strong>Why visit:</strong> Hangzhou''s most distinctively designed café — a collision of industrial heritage and tea culture. International visitors can experience both at once.</li></ul><h2>6. Process Coffee — Technical Precision Specialty Café</h2><ul><li><strong>Specialty:</strong> The name "Process" refers to both coffee processing methods and the art of preparation. Four grinders are each dedicated to a specific role, and two Decent variable-parameter espresso machines achieve exceptional extraction precision through a long-pull short-extract method that captures the finest front-end flavors. The bean menu is refreshed monthly, sourcing from respected roasters at home and abroad.</li><li><strong>Signature drinks:</strong> Light-roast Americano and milk coffee running in parallel; SEY Ethiopian natural heirloom variety pour-over (white floral and lychee notes); beans from Panamanian local roasters</li><li><strong>Food:</strong> No set menu; focused entirely on coffee</li><li><strong>Address:</strong> 212 Tongren Street, Binjiang District</li><li><strong>Why visit:</strong> A paradise for hardcore technique enthusiasts. Four grinders, two Decent machines, a monthly-rotating bean menu — every cup is a precision flavor experiment.</li></ul><h2>7. Eternità Cafe — Hangzhou''s First Authentic Italian Espresso Bar</h2><ul><li><strong>Specialty:</strong> Opened in 2024, the only specialty café in Hangzhou devoted to traditional Italian espresso culture. Uses 100% Arabica beans imported directly from Italy and prepared by hand in the traditional manner. The team was trained by Italy''s AICAF coffee academy; all baristas hold SCA certification and travel to Italy regularly for further training.</li><li><strong>Signature drinks:</strong> Bicerin (Turin classic: espresso + hot chocolate + cream in three distinct layers), Viennese Cappuccino, Marocchino (cocoa powder + espresso)</li><li><strong>Food:</strong> Health-conscious pastries, lemon cake</li><li><strong>Address:</strong> 37 Tongpu Road, Gudang Street, Xihu District</li><li><strong>Why visit:</strong> A direct window into the dialogue between Chinese and Italian coffee culture. The Bicerin, a century-old Turin classic, has nearly vanished in China — here it is served in its original form, well worth making a special trip for.</li></ul><h2>8. Bajiao Cup Coffee (Abutlamb Coffee) — A Local Specialty Brand that Started as a Tiny Stand</h2><ul><li><strong>Specialty:</strong> Born as a miniature coffee stand at 87 Zhongshan North Road, built on the philosophy of good coffee at an honest price with fast service. The brand grew rapidly in popularity and now has multiple locations across Hangzhou, along with its own roasting workshop. The original location has been renovated with floor-to-ceiling windows and a clean industrial aesthetic. The menu features SOE single-origin espresso and seasonal limited specials.</li><li><strong>Signature drinks:</strong> SOE single-origin Americano, seasonal creative specials</li><li><strong>Food:</strong> Light snacks (menu varies by season)</li><li><strong>Address:</strong> 87 Zhongshan North Road, Gongshu District (founding location); more than ten additional branches across Hangzhou</li><li><strong>Why visit:</strong> A local take on the international coffee stand culture — from a tiny stand to a brand with its own roasting workshop. Visiting the original location offers the most down-to-earth taste of Hangzhou''s everyday coffee scene.</li></ul><h2>9. Sanhua House (Mihhanaya) — A Family Café Growing Slowly</h2><ul><li><strong>Specialty:</strong> The owner describes this as "a family café growing slowly" — drinking here feels like visiting a friend''s home. A lemon tree grows outside the window, changing with the seasons; children sometimes run through, and the atmosphere is warm and unforced. In recent years the café has shifted from deep-roast imported beans to direct-fire house-roasted light roasts, focused on expressing terroir. The Sanhua Blend is seasonal, with a recipe that changes throughout the year.</li><li><strong>Signature drinks:</strong> Sanhua Blend (seasonal recipe, for example Ethiopian and Honduran), direct-fire house-roasted pour-over</li><li><strong>Food:</strong> Handmade pastries (a consistent lineup of cakes and desserts)</li><li><strong>Address:</strong> 46 Shangshao Road, Gongshu District (across from Jiajia Lane Kindergarten)</li><li><strong>Why visit:</strong> Hangzhou''s warmest family-style café. The simple pairing of handmade sweets and house-roasted coffee makes you forget the busy world outside. International visitors will find here the authentic warmth of everyday life in Hangzhou.</li></ul><h2>10. Pixiang Workshop — Japanese Aesthetic Self-Roasting Waystation</h2><ul><li><strong>Specialty:</strong> After relocating from a 23rd-floor high-rise to a riverside neighborhood, the café has settled into a gentle new chapter. The spacious bar is well-equipped and a hand-written menu preserves a sense of human warmth. The house-roasting style is calm, balanced, and nuanced — not chasing dramatic flavors, more like a fine tea with a long, lingering finish. Japanese wood interiors glow warmly, the atmosphere like light borrowed from another era.</li><li><strong>Signature drinks:</strong> House-roasted Panama Hacienda Blanca Gesha pour-over (delicate white florals), deep-roast latte (nutty and buttery)</li><li><strong>Food:</strong> No set menu; focused entirely on coffee</li><li><strong>Address:</strong> 39–41 Chaomin Temple Lane, Gongshu District</li><li><strong>Why visit:</strong> A perfect fusion of Japanese aesthetic sensibility and house roasting. The steady, unhurried style makes every visit feel like returning to a comfortable, familiar place — ideal for visitors who like to drink coffee quietly.</li></ul><h2>Practical Tips</h2><ul><li><strong>Getting there:</strong> Most cafés are clustered along Hai''er Lane and Zhongshan North Road in Gongshu District, the Wushan and Hefang Street area in Shangcheng District, and Tongren Street in Binjiang District. A combination of metro and walking is recommended.</li><li><strong>Reservations:</strong> Zidongwoxi Coffee recommends booking in advance on weekends. Ceremorning and Random Play opens only three to four days a week — check its official social media for current opening days before you go.</li><li><strong>Language:</strong> Most independent cafés do not have English menus. Taking screenshots of the Chinese addresses in this guide for navigation is recommended. Parking Coffee, Eternità Cafe, and Process Coffee have international backgrounds and are more visitor-friendly.</li><li><strong>Payment:</strong> Alipay and WeChat Pay are universally accepted; some shops take cash. Make sure your mobile payment is set up and ready.</li></ul><p>*All information is based on publicly available data from 2025–2026. Please verify current hours, addresses, prices, and reservation policies through each shop''s official channels before visiting. The Dianping app or each shop''s social media is recommended for a final check.*</p>',
  '[]'::jsonb,
  0,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
