INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'hangzhou_food_suipo',
  'hangzhou',
  'Hangzhou Food Guide',
  '杭州美食推荐指南',
  'Compiled from the real restaurant reviews of master chef Sui Po (social media handle: "Techu Sui Bian").',
  '🍜',
  'Food',
  ARRAY[]::TEXT[],
  '<h2>One — Fuyuanju (Hefang Street Branch)</h2><ul><li><strong>Address:</strong> 35 Hefang Street, Shangcheng District, Hangzhou</li><li><strong>Recommended dishes:</strong> Crispy pork intestine (Sui Po finished his serving, exclaimed "absolutely delicious," and immediately ordered a second); stir-fried gizzard and cuttlefish (duck gizzard and scored cuttlefish flash-fried together, rated "unbeatable"); Ningbo-style shredded eel; Shaoxing-wine-marinated crab</li><li><strong>Style:</strong> An authentic Hangzhou cuisine neighborhood restaurant with a Michelin Bib Gourmand recommendation. Lively, local atmosphere loved by both residents and visitors. Average spend: 80–150 yuan per person.</li></ul><h2>Two — Shanwaishan Restaurant</h2><ul><li><strong>Address:</strong> 8 Yuquan Road, Xihu District, Hangzhou (inside the North Gate of Hangzhou Botanical Garden)</li><li><strong>Recommended dishes:</strong> Beggar''s Chicken (138 yuan — Sui Po said it is more deeply flavored than the famous Lou Wai Lou, fragrant and tender to the bone); crab roe fish maw (78 yuan — quality crab roe paired with fish maw, worth trying); crispy deep-fried hairtail (68 yuan — rated "very good value" by Sui Po)</li><li><strong>Style:</strong> A century-old, time-honored Hangzhou cuisine institution set inside the botanical garden, surrounded by green hills and shaded trees, with a peaceful and refined dining atmosphere. Average spend: 150 yuan or more per person.</li></ul><h2>Three — Wojia Xiaoguan (Xixi Shiji Center Branch)</h2><ul><li><strong>Address:</strong> Unit 116, Building 6, Phase One, Greentown Xixi Shiji Center, Xihu District, Hangzhou</li><li><strong>Recommended dishes:</strong> Rock garlic rice cake (98 yuan — thick, savory sauce with the fragrance of rock garlic fully absorbed into soft, chewy rice cake); oil-braised hairtail (268 yuan — firm, sweet flesh with cross-cut scoring that ensures even flavor throughout)</li><li><strong>Style:</strong> A Taizhou-style home-cooking seafood restaurant tucked inside a residential compound, with just six tables — yet it earned Sui Po''s across-the-board praise. Fresh ingredients, authentic flavors. Average spend: 150–250 yuan per person.</li></ul><h2>Four — Longjing Caotang</h2><ul><li><strong>Address:</strong> 399 Longjing Road, Xihu District, Hangzhou</li><li><strong>Recommended dishes:</strong> "She De" (228 yuan — over five kilograms of seasonal greens are gathered, but only the innermost tender hearts are used to make a single bowl; the texture is extraordinarily silky and delicate); tender ginger stir-fried chicken (precise heat control, an ideal seasonal dish for summer); braised pork belly</li><li><strong>Style:</strong> An upscale private dining restaurant in a classical Jiangnan garden setting beside the Longjing tea fields, with deep cultural character and attentive service. Sui Po praised it as a place that "really knows how to tell a story." Average spend: 800 yuan or more per person.</li></ul><h2>About Sui Po</h2><p>Sui Po, known on Douyin and Bilibili as "Techu Sui Bian," has worked as a chef for over 30 years and trained under Zheng Xiusheng, master chef of China''s state banquets. Reviewing restaurants from the perspective of a senior professional chef, he delivers candid, expert assessments with a direct and often witty voice. He has earned millions of followers across Chinese social media platforms and is widely regarded as one of the most trustworthy food reviewers in China.</p><p>*The information above is compiled from Sui Po''s public restaurant-visit videos and other online sources. Actual menu prices and opening hours are subject to each restaurant''s official announcements.*</p>',
  '[]'::jsonb,
  3,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
  city_id = EXCLUDED.city_id,
