INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'nanjing_michelin',
  'nanjing',
  'Nanjing Michelin Restaurant Guide — App Venue Listing Copy',
  '南京米其林餐厅指南 · App景点列表页文案',
  'Note: This copy is written for the Nanjing Michelin Restaurants section of the App venue listing.',
  '🍽',
  'Dining',
  ARRAY[]::TEXT[],
  '<h2>One-Star Michelin Restaurants (4 venues)</h2><h3>1. Di Yue Xuan</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> The Ritz-Carlton Nanjing, 18 Zhongshan Road, Xuanwu District <strong>Opening hours:</strong> 11:30–14:30, 17:30–21:30 <strong>Phone:</strong> +86 25 6956 3723 <strong>Average spend:</strong> 600–900 yuan</p><h2>About the restaurant:</h2><p>Perched on an upper floor of The Ritz-Carlton Nanjing with panoramic city views, Di Yue Xuan focuses on refined Cantonese cuisine. The kitchen works with fresh seasonal ingredients and demonstrates a high level of technical precision. The setting is elegant and the service attentive — Nanjing''s benchmark for high-end Cantonese dining.</p><h2>Signature dishes:</h2><ul><li>House roast goose: crisp skin, succulent meat, richly rendered fat</li><li>Steamed grouper: delicate, clean-flavoured, served in its own natural juices</li><li>Premium har gow: thin wrapper, generous filling, a satisfying bounce in every bite</li></ul><h2>Why visit:</h2><p>A Michelin one-star experience and the ideal choice for a formal dinner or a special occasion, with technically accomplished Cantonese cooking and top-quality ingredients.</p><h3>2. Jiang Nan Zao · Yun Fu</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> Shangri-La Hotel Nanjing, 329 Zhongyang Road, Gulou District <strong>Opening hours:</strong> 11:00–14:00, 17:00–21:30 <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 300–500 yuan</p><h2>About the restaurant:</h2><p>Chef Hou Xinqing, a master of Huaiyang cuisine, leads the kitchen at this Michelin one-star restaurant inside the Shangri-La Hotel Nanjing. The elegant setting and a cooking philosophy that blends tradition with contemporary creativity make this one of the city''s most distinguished dining rooms.</p><h2>Signature dishes:</h2><ul><li>Wensi tofu soup with crabmeat: knife work of extraordinary precision, the tofu cut as fine as silk threads</li><li>Braised lion''s head meatball with crab roe: perfectly balanced fat and lean, melts on the tongue</li><li>House braised pork belly: deep mahogany colour, rich without being heavy</li></ul><h2>Why visit:</h2><p>A Michelin one-star restaurant and a Black Pearl one-diamond venue. The gold standard for Huaiyang cuisine — an ideal experience for visitors wanting to understand the refined flavours of the Jiangnan tradition.</p><h3>3. Meng Du Hui</h3><p><strong>Cuisine:</strong> Anhui <strong>Address:</strong> Unit 65, Nanjing Olympic Sports Center, 222 Jiangdong Middle Road, Jianye District <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> +86 25 8669 0777 <strong>Average spend:</strong> 400–600 yuan</p><h2>About the restaurant:</h2><p>Meng Du Hui occupies a spacious setting decorated throughout in wood and furnished in the style of traditional Huizhou architecture. The menu centres on Anhui cuisine, with most ingredients sourced directly from Anhui Province, presenting the authentic flavours of the tradition.</p><h2>Signature dishes:</h2><ul><li>Fermented mandarin fish: slow-fermented in the Anhui tradition, with firm and dense flesh; available braised in red sauce or braised with chilli</li><li>Huizhou hairy tofu: crisp outside, silky inside, best dipped in chilli sauce</li><li>Hu Shi''s scholar''s casserole: a multi-layered slow-cooked pot of intense, fragrant depth, named after the scholar Hu Shi</li></ul><h2>Why visit:</h2><p>A newly added Michelin one-star restaurant. The best representation of Anhui cuisine in Nanjing — worth visiting both for the distinctive flavours and for the immersive Huizhou architectural setting.</p><h3>4. Pin Ning Fu</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> Floor 39, The Ritz-Carlton Nanjing, 18 Zhongshan Road, Xuanwu District <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 300–500 yuan</p><h2>About the restaurant:</h2><p>On the 39th floor of The Ritz-Carlton Nanjing, Pin Ning Fu looks out over Xuanwu Lake and Purple Mountain. An experienced team of chefs concentrates on the authentic transmission of Huaiyang culinary tradition, with a menu spanning classic dishes and seasonal specialities.</p><h2>Signature dishes:</h2><ul><li>Crystal pork terrine with vinegar pearls: translucent, springy, with tiny bursts of sharp vinegar</li><li>Wensi tofu soup with crabmeat: clear broth, the tofu cut as fine as silk threads</li><li>Huaiyang braised eel: tender eel in a fragrant, deeply savoury sauce</li></ul><h2>Why visit:</h2><p>A newly added Michelin one-star restaurant. A sky-high dining room with sweeping views — ideal for a romantic evening or a formal dinner.</p><h2>Bib Gourmand Restaurants (21 venues)</h2><h3>5. Fang Po Rice Cake Shop</h3><p><strong>Cuisine:</strong> Nanjing street food <strong>Address:</strong> 50 Wangfu Street, Qinhuai District <strong>Opening hours:</strong> 04:00–18:30 <strong>Phone:</strong> +86 25 8420 4310 <strong>Average spend:</strong> 15–30 yuan</p><h2>About the restaurant:</h2><p>This rice cake shop started as a neighbourhood breakfast stall and has kept its doors open for more than forty years, still drawing queues and communal table sharing every day. The menu covers classic Nanjing street foods: sweet taro shoots in osmanthus syrup, glutinous rice balls in sweet fermented rice wine, spicy soup, and more.</p><h2>Signature dishes:</h2><ul><li>Black rice ball: available at breakfast only, with a wide range of fillings — honest and deeply flavoured</li><li>Sweet taro shoots: soft and smooth, gently sweet, with a fragrant thread of osmanthus running through</li><li>Glutinous rice balls in sweet fermented rice wine: sweet without cloying, fragrant with fermented rice wine</li></ul><h2>Why visit:</h2><p>A Michelin Bib Gourmand restaurant and an authentic window onto Nanjing''s traditional breakfast culture. Affordable, unpretentious, and genuinely local.</p><h3>6. Xiao Pan Ji Duck Blood Vermicelli Soup</h3><p><strong>Cuisine:</strong> Nanjing street food <strong>Address:</strong> Longtai Building, 198 Zhongshan East Road, Qinhuai District <strong>Opening hours:</strong> 08:00–20:00 <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 20–35 yuan</p><h2>About the restaurant:</h2><p>Founded by Pan Linhu and Zhou Zhiqin in 2005, the restaurant now handles around 800 dine-in and delivery orders a day, with peak days approaching a thousand bowls. The broth is simmered for five to six hours with no MSG added.</p><h2>Signature dishes:</h2><ul><li>Duck blood and vermicelli soup: old-duck broth base, served with duck blood, duck intestine, and duck liver — deeply flavoured and aromatic</li><li>Duck-fat flaky pastry: crisp and fragrant with duck fat</li><li>Mixed duck offal and vermicelli soup: generous toppings, excellent value</li></ul><h2>Why visit:</h2><p>A Michelin Bib Gourmand restaurant and the benchmark for Nanjing''s duck blood vermicelli soup. Rich broth, fresh ingredients — an essential stop for experiencing Nanjing''s "Duck Capital" food culture.</p><h3>7. Li Ji Halal Restaurant</h3><p><strong>Cuisine:</strong> Halal street food <strong>Address:</strong> To be confirmed <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 20–40 yuan</p><h2>About the restaurant:</h2><p>A long-established halal street food shop in Nanjing, renowned for beef pot stickers and beef wontons. Traditional preparation methods are maintained, the ingredients are fresh, and the flavours are authentic.</p><h2>Signature dishes:</h2><ul><li>Beef pot stickers: crisp skin, tender and juicy beef filling</li><li>Beef wontons: thin wrapper, generous filling, light and clean broth</li><li>Beef soup dumplings: rich in soup, tender and fresh</li></ul><h2>Why visit:</h2><p>A Michelin Bib Gourmand restaurant and the go-to for Nanjing halal street food. Affordable, distinctive, and a good introduction to Nanjing''s Muslim food culture.</p><h3>8. Cui Jie Snacks</h3><p><strong>Cuisine:</strong> Nanjing street food <strong>Address:</strong> To be confirmed <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 15–30 yuan</p><h2>About the restaurant:</h2><p>A neighbourhood snack shop in Nanjing serving home-style food at affordable prices. A favourite with locals, the environment is unpretentious and the food is genuine.</p><h2>Signature dishes:</h2><ul><li>To be confirmed</li><li>To be confirmed</li><li>To be confirmed</li></ul><h2>Why visit:</h2><p>A Michelin Bib Gourmand restaurant, the kind of small local shop where Nanjing residents eat day to day. Ideal for a taste of everyday Nanjing home cooking at a fair price.</p><h3>9. Wu Ming Lao Lu Noodles</h3><p><strong>Cuisine:</strong> Noodle dishes <strong>Address:</strong> To be confirmed <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 15–25 yuan</p><h2>About the restaurant:</h2><p>A time-honoured Nanjing noodle shop built around a slow-cooked braised broth. The noodles have a satisfying chew, the broth is deep and complex, and this is a daily staple for many Nanjing residents.</p><h2>Signature dishes:</h2><ul><li>Braised broth noodles: rich, full-bodied broth, chewy noodles</li><li>To be confirmed</li><li>To be confirmed</li></ul><h2>Why visit:</h2><p>A Michelin Bib Gourmand restaurant and a representative of Nanjing''s noodle culture. Ideal for experiencing everyday Nanjing eating at an honest price.</p><h2>Michelin Selected Restaurants (16 venues)</h2><h3>10. Mei Yuan</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> Second floor, Jinling Hotel, 2 Hanzhong Road, Gulou District <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> 025-8630 8888 <strong>Average spend:</strong> 200–350 yuan</p><h2>About the restaurant:</h2><p>Mei Yuan takes the plum blossom as its design theme and brings a graceful, understated atmosphere to bear on the deep traditions of Huaiyang and Jinling cuisine. Dishes that have been on the menu for years — including braised pounded eel and traditional-style salted duck — carry the full weight of Jiangnan banquet heritage.</p><h2>Signature dishes:</h2><ul><li>Braised pounded eel: eel beaten until tender then slow-braised — a uniquely satisfying texture</li><li>Traditional-style salted duck: exceptionally tender flesh, a well-balanced salty savouriness</li><li>Lion''s head meatball with crab roe: perfectly balanced fat and lean, melts on the tongue</li></ul><h2>Why visit:</h2><p>A Michelin selected restaurant and the flagship dining room of the Jinling Hotel. Huaiyang and Jinling cuisine at their most refined — ideal for experiencing Nanjing''s high-end dining culture.</p><h3>11. Yu Chuan</h3><p><strong>Cuisine:</strong> Sichuan <strong>Address:</strong> 1912 District, 129 Hongwu North Road, Xuanwu District <strong>Opening hours:</strong> To be confirmed <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 150–250 yuan</p><h2>About the restaurant:</h2><p>Yu Chuan brings the spirit of Jichuan — a celebrated Sichuan restaurant that made a name for itself in Beijing — to Nanjing, through a collaboration between the Yihe brand and culinary entrepreneur Duan Yu. The restaurant is set inside a century-old Republican-era building once known as the Gongyu Lianhuanshe, a former social club within the 1912 District.</p><h2>Signature dishes:</h2><ul><li>Mapo tofu with snow-marbled beef: tender beef, silky tofu</li><li>To be confirmed</li><li>To be confirmed</li></ul><h2>Why visit:</h2><p>A Michelin selected restaurant and a showcase for contemporary Sichuan cooking. A compelling blend of Republican-era architecture and bold, modern flavours.</p><h3>12. Jiang Nan Zao</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> Shangri-La Hotel Nanjing, 329 Zhongyang Road, Gulou District <strong>Opening hours:</strong> 11:00–14:00, 17:00–21:30 <strong>Phone:</strong> To be confirmed <strong>Average spend:</strong> 150–250 yuan</p><h2>About the restaurant:</h2><p>A Michelin selected restaurant and Black Pearl one-diamond venue, sharing its home at the Shangri-La Hotel Nanjing with the one-star Jiang Nan Zao · Yun Fu, but positioned at a more accessible price point. The focus remains on classic Huaiyang dishes, delivered by an experienced kitchen team.</p><h2>Signature dishes:</h2><ul><li>House braised pork belly: deep mahogany colour, rich without being heavy</li><li>House-style veal: tender, with a deep, savoury sauce</li><li>Huaiyang braised eel: tender eel, technically precise cooking</li></ul><h2>Why visit:</h2><p>A Michelin selected restaurant offering Huaiyang cuisine at a relatively accessible price. The ideal introduction to the essence of Huaiyang cooking.</p>',
