INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'nanjing_districts_citywalk',
  'nanjing',
  'Nanjing Cultural Districts: A Citywalk Guide',
  '南京文化街区 Citywalk 指南',
  'A neighbourhood-by-neighbourhood walking guide to Nanjing for foreign visitors, covering historic sites, folk culture, architecture, arts, and industrial heritage.',
  '🚶',
  'Citywalk',
  ARRAY[]::TEXT[],
  '<h2>1. Laomendong Historic Block</h2><p><strong>Character:</strong> Laomendong preserves the traditional street layout of Nanjing''s old south city. It is home to artisans practising Jinling sutra-engraving, Nanjing Baju folk ballad, handmade kite-making, bamboo carving, and paper cutting, alongside authentic Nanjing street food including duck blood vermicelli soup and sweet taro shoots.</p><p><strong>Address:</strong> East of Zhonghua Gate, Qinhuai District, Nanjing; bounded to the north by Changle Road and to the south by the Ming City Wall.</p><p><strong>Why visit:</strong> Foreign visitors can experience Nanjing''s traditional neighbourhood life, folk crafts, and street food all in one compact area. The block is pedestrian-friendly, sits right next to the Ming City Wall, and makes an ideal half-day wander — the best starting point for feeling the everyday warmth of old Nanjing.</p><h2>2. Confucius Temple and the Qinhuai River Scenic Area</h2><p><strong>Character:</strong> A National Grade-5A Scenic Area centred on the Confucius Temple complex, with the Ten-Mile Qinhuai River as its main axis. Highlights include the China Imperial Examination Museum, the Zhonghua Gate barbican, and Zhan Garden. Evening boat cruises along the Qinhuai River are a particular draw.</p><p><strong>Address:</strong> 53 Gongyuan West Street, Qinhuai District, Nanjing.</p><p><strong>Why visit:</strong> Nanjing''s most iconic cultural destination. Foreign visitors can take in the imperial examination culture, Ming and Qing architecture, and the lantern-lit Qinhuai River at night, while sampling the area''s celebrated street snacks. An essential stop for understanding Nanjing''s historical depth.</p><h2>3. Yihe Road Republican-Era Villa District</h2><p><strong>Character:</strong> Developed from the 1930s onwards, this is the best-preserved collection of Republican-era villa architecture in China, with 285 courtyard compounds and 264 individual buildings surviving. Tree-lined boulevards, pale render, and European-inflected architecture have earned it a reputation as a "showcase of modern architectural styles."</p><p><strong>Address:</strong> Yihe Road, Gulou District, Nanjing (approximately a 5-minute walk from Yunnan Road Station on Metro Line 4).</p><p><strong>Why visit:</strong> Walking beneath the plane trees here feels like stepping back into Republican-era China. The entire district is free to enter at any time, the buildings are superb for photography, and this is the natural first choice for foreign visitors interested in Nanjing''s modern history and architectural character.</p><h2>4. Nanjing 1912 District</h2><p><strong>Character:</strong> A cluster of 19 Republican-era courtyard-style buildings around four plazas, named for the year 1912. Grey brick, dark roof tiles, and a blend of Chinese and Western design elements now house a lively mix of restaurants, bars, and creative shops.</p><p><strong>Address:</strong> 8 Changjiang Hou Street, Xuanwu District, Nanjing (immediately west of the Presidential Palace).</p><p><strong>Why visit:</strong> A seamless blend of Republican-era architecture and contemporary city nightlife. Foreign visitors can tour the Presidential Palace by day and come back here for dinner and drinks in the evening — a neat way to feel the continuity between Nanjing''s layered history and its living present.</p><h2>5. Xinanli Historic Block</h2><p><strong>Character:</strong> Built around Gan Xi Former Residence — the largest and best-preserved private Qing-dynasty residence remaining in Nanjing. The architecture follows the classic Jinling residential style of grey brick, small tiles, and decorative gable walls with carved lattice windows. Contemporary leisure businesses are woven into the historic fabric.</p><p><strong>Address:</strong> 400 Zhongshan South Road, Qinhuai District, Nanjing (at the junction of Zhongshan South Road and Shengzhou Road).</p><p><strong>Why visit:</strong> Quieter and more intimate than the Confucius Temple area, Xinanli is ideal for visitors who want to spend time in a traditional Jinling courtyard residence and experience the domestic culture of a Qing-dynasty elite household. A rewarding alternative for those looking to step away from the main tourist crowds.</p><h2>6. Xiao Xihu Historic Quarter</h2><p><strong>Character:</strong> The most complete surviving Ming and Qing residential streetscape in Nanjing''s old south city. A "micro-renewal" approach to regeneration has preserved the feel of a living neighbourhood — original residents remain — while introducing cafes and creative studios alongside the traditional homes.</p><p><strong>Address:</strong> 21 Madao Street, Qinhuai District, Nanjing (immediately north of Laomendong).</p><p><strong>Why visit:</strong> A model of how old and new can share a neighbourhood without one erasing the other. Foreign visitors can see how a traditional urban street adapts to contemporary life while retaining its essential character — and the atmosphere is excellent for photography.</p><h2>7. Changjiang Road Cultural District</h2><p><strong>Character:</strong> A cultural corridor stretching about 1.8 kilometres, linking major landmarks including the Presidential Palace, the Museum of the Six Dynasties, the Jiangsu Provincial Art Museum, and the Librairie Avant-Garde bookshop.</p><p><strong>Address:</strong> Changjiang Road, Xuanwu District, Nanjing (running east from Longpan Middle Road to Zhongshan Road in the west).</p><p><strong>Why visit:</strong> A single street that concentrates the essence of Nanjing''s modern cultural history. Half a day on foot takes in multiple museums and historic buildings at a comfortable pace, making this one of the most time-efficient cultural walks in the city.</p><h2>8. Taogu Village and Nanxiu Village Arts Quarter</h2><p><strong>Character:</strong> The creative neighbourhood around Nanjing University, with independent cafes, vintage clothing shops, design boutiques, and painted murals. Jinyin Street has a popular "We Love Nanjing So Much" photo wall, and Nanxiu Village is home to some of the city''s earliest independent coffee shops.</p><p><strong>Address:</strong> Jinyin Street — Nanxiu Village — Taogu New Village, Gulou District (Metro Line 4, Yunnan Road Station).</p><p><strong>Why visit:</strong> Nanjing''s gathering point for artists, students, and the creative community. Foreign visitors can experience how younger Nanjing residents live — browsing vintage clothing, trying independent coffee, shooting street photography — and discover the city''s relaxed, artistic side.</p><h2>9. Grand Bao''en Temple Heritage Park</h2><p><strong>Character:</strong> Built over the excavated remains of a Ming imperial monastery and designated a National First-Class Museum. The original site once held a glazed pagoda renowned as one of the Seven Wonders of the Medieval World. Modern technology is used throughout to bring the Buddhist heritage to life.</p><p><strong>Address:</strong> 1 Yuhua Road (south of Zhonghua Gate), Qinhuai District, Nanjing (Metro Line 1, Zhonghua Gate Station).</p><p><strong>Why visit:</strong> A place where foreign visitors can explore Chinese Buddhist culture and Ming imperial architecture in an immersive setting. The heritage exhibition halls use light, sound, and digital technology to create a strong sense of atmosphere, and climbing the glass pagoda offers a panoramic view over the Qinhuai River landscape.</p><h2>10. Chenguang 1865 Creative Park</h2><p><strong>Character:</strong> Formerly the Jinling Arsenal, founded by Li Hongzhang in 1865 as the cradle of China''s modern national defence industry. The park retains its original Qing and Republican-era industrial buildings, which now house an art gallery, design studios, and a creative market.</p><p><strong>Address:</strong> 388 Yingtian Avenue, Qinhuai District, Nanjing (on the Qinhuai River).</p><p><strong>Why visit:</strong> A century-old arsenal reborn as a creative hub. Foreign visitors can admire the industrial heritage architecture up close, browse the creative market and art exhibitions, and see what adaptive reuse of industrial heritage looks like in a Chinese city.</p><p>*All information in this guide is compiled from public sources. Actual admission prices, opening hours, and booking policies should be verified through official venue channels before your visit. Foreign visitors are advised to check for the latest information before setting out.*</p>',
  '[]'::jsonb,
  3,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
