INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'shanghai_michelin',
  'shanghai',
  'Shanghai Michelin Guide — Restaurant Listings for the App',
  '上海米其林指南 — 餐厅介绍文案',
  'The Bib Gourmand designation recognizes restaurants offering high-quality food at affordable prices.',
  '🍽',
  'Dining',
  ARRAY[]::TEXT[],
  '<h2>One: Three-Star Michelin Restaurants (Shanghai — 1 restaurant)</h2><h3>1. Taian Table</h3><p><strong>Cuisine:</strong> Innovative <strong>Address:</strong> Yuyuan Li, Lane 465 Zhenning Road, Changning District</p><p>Shanghai''s only three-star Michelin restaurant, led by German chef Stefan Stiller. The restaurant has an open kitchen where diners can watch the entire team cook. The tasting menu crosses borders freely, weaving German influences with Asian elements like kimchi and curry for rich layers of flavor and texture. The wine list focuses on fine German bottles that complement the food beautifully. Reservations online only.</p><h2>Two: Two-Star Michelin Restaurants (Shanghai — 12 restaurants)</h2><h3>2. Fu He Hui</h3><p><strong>Cuisine:</strong> Vegetarian <strong>Address:</strong> 1037 Yuyuan Road, Jing''an District</p><p>Shanghai''s finest vegetarian restaurant, elevated from one star to two stars in 2025. Both the decor and the dishes carry deep Zen influences; only tasting menus are served. The chef sources seasonal ingredients from across China and changes the menu with the four seasons, incorporating many traditional labor-intensive techniques. Pairing with Chinese tea is recommended — a sip of fine tea between bites of vegetarian food makes for a distinctive, meditative experience.</p><h3>3. Tang Court (newly elevated to two stars)</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> 5th floor, The Langham Shanghai, Xintiandi, Huangpu District</p><p>Consecutively Michelin-starred for ten years, elevated to two stars in 2026. The interior is richly decorated with Chinese motifs, and the kitchen pairs traditional Cantonese cooking with creative contemporary touches. The food is refined, the service professional and attentive. The restaurant has simultaneously held a Forbes Travel Guide Four-Star certification — a top-tier address for Cantonese fine dining.</p><h3>4. Tou Zao (newly elevated to two stars)</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Shanghai Centre, Jing''an District</p><p>Elevated from one star to two stars in 2026. The kitchen team comes from Guangdong and handles its ingredients with scrupulous care. The dishes balance traditional Cantonese technique with a contemporary aesthetic, emphasizing the natural flavor of every ingredient. Well suited to business dining and high-end occasions.</p><h3>5. Jing Xi Hui Changning (newly elevated to two stars)</h3><p><strong>Cuisine:</strong> Teochew (Chaozhou) <strong>Address:</strong> 1665 Hongqiao Road, Changning District</p><p>Elevated from one star to two stars in 2026 — Shanghai''s benchmark Teochew restaurant. Founder Du Jianqing is originally from Puning in the Chaozhou area and has devoted over twenty years to refining Teochew cooking. Signature braised goose head uses Lion Head geese from Chenghai, slow-braised to depth; crispy golden sea cucumber is crunchy outside and soft within; the clear broth conch slice is intensely savory. The restaurant occupies a freestanding villa with several private dining rooms.</p><h3>6. 8½ Otto e Mezzo Bombana</h3><p><strong>Cuisine:</strong> Italian <strong>Address:</strong> The Bund, Huangpu District</p><p>Founded by Italian chef Umberto Bombana, Shanghai''s premier Italian restaurant. Pasta and bread are all hand-made; the signature menu centers on seafood for a complete dining experience. Seasonal truffle dishes are not to be missed. The wine list focuses on Italian labels; the sommelier can suggest pairings.</p><h3>7. Da Vittorio</h3><p><strong>Cuisine:</strong> Italian <strong>Address:</strong> Huangpu District</p><p>A family-run Michelin restaurant from Italy, celebrated for its classic Italian cooking. Dishes follow family recipes and emphasize the inherent flavor of fine ingredients and elegant presentation. Signature dishes including caviar and hand-made pasta showcase the essence of Italian culinary craftsmanship, complemented by a curated Italian wine selection for a full fine-dining experience.</p><h3>8. Xi Yue Number Eight Huangpu</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Huangpu District</p><p>Celebrated for offering high-quality Cantonese food at notably accessible prices — the "best-value two-star Michelin" restaurant. Signature crystal shrimp dumplings are made with wafer-thin translucent skin wrapped around whole tiger prawns, fresh and springy. Roasted meats, dim sum, and seafood are all consistently excellent — an outstanding address for authentic Cantonese cooking.</p><h3>9. Yu Bao Xuan</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Huangpu District</p><p>A high-end Cantonese restaurant known for exceptional craft and premium ingredients. The menu covers classic Cantonese standards from dim sum and roasted meats to seafood and braised dishes, all executed with great skill. Roasted squab is crispy on the outside, tender inside; the signature salted egg yolk lava bun is silkily molten — dishes that guests return for repeatedly.</p><h3>10. Bao Li Xuan</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> The Bulgari Hotel Shanghai, Jing''an District</p><p>Set within the Bulgari Hotel, the environment is refined and elegant. The kitchen specializes in traditional Cantonese cooking, with a team that has deep command of both heat control and knife technique. Ms. Guo Hongli, winner of the 2026 Service Award, works here — recognized for her gracious manner and thoughtful attention, creating a seamless and relaxed dining experience for every guest.</p><h3>11. One Zero Two Small Restaurant</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Huangpu District</p><p>A refined Cantonese restaurant celebrated for its delicate technique and high-quality ingredients. The menu balances tradition and innovation. The signature black truffle lobster noodle soup has a deep, rich broth and sweet lobster meat. The dim sum is equally outstanding — crystal shrimp dumplings with thin skin and fresh filling exemplify the Cantonese virtue of painstaking craft.</p><h3>12. Ji Pin Xuan</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Huangpu District</p><p>A high-end Cantonese restaurant rooted in classic technique and incorporating contemporary elements. Ingredient sourcing is rigorous; seafood, roasted meats, and braised dishes all maintain a high standard. The setting is elegant and the atmosphere refined — suitable for business entertaining and formal gatherings.</p><h3>13. Rong Fu Yan</h3><p><strong>Cuisine:</strong> Taizhou <strong>Address:</strong> Huangpu District</p><p>Taizhou seafood cooking is at the heart of this restaurant''s identity, with much of the produce sourced from the East China Sea. Dishes are cooked simply, letting the ingredients speak; traditional Taizhou seasoning gives the food a clear, layered savoriness. An excellent window onto the coastal culinary culture of the Zhejiang coast.</p><h2>Three: One-Star Michelin Restaurants (Shanghai — 38 restaurants)</h2><h3>14. Canton Table</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> The Bund, Huangpu District</p><p>Located on the Bund with floor-to-ceiling windows overlooking the Huangpu River. The interior is minimal, with paintings of qipao-clad women evoking old Shanghai glamour. The menu centers on Cantonese cooking including roasted meats and dim sum. Ask for a window seat — Cantonese food and a river view on the Bund make for a uniquely Shanghai dining experience.</p><h3>15. Cheng Long Hang Crab Palace Huangpu</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Huangpu District</p><p>A Shanghainese restaurant celebrated for its crab banquets. During the autumn crab season, the hairy crab dishes are exceptional — crab roe tofu, steamed hairy crab, and other classics are supremely fresh and savory. The dining room has an antique, Jiangnan character — an ideal place to eat crab and enjoy the season.</p><h3>16. Da Dong Xuhui</h3><p><strong>Cuisine:</strong> Fashionable Chinese <strong>Address:</strong> Xuhui District</p><p>The classic Da Dong Roast Duck restaurant, famous nationwide for its crispy, non-greasy duck. The skin crackles; dipped in white sugar, it melts on the tongue. Dong-style braised sea cucumber and tomato crispy mushroom salad are also widely praised. Dishes are plated with artistry — an experience for both palate and eye.</p><h3>17. Fabula (newly starred)</h3><p><strong>Cuisine:</strong> Innovative <strong>Address:</strong> 720 Weihai Road, Jing''an District</p><p>Newly awarded one star in 2026 — the name means "script." Led by a young chef team alumni of top restaurants including Taian Table, it occupies a hidden loft above a wine bar and operates as a chef''s table. Three chefs bring the flavors of Ningbo, Guangdong, and other regions into a French fine-dining framework. The signature house-made sourdough uses a three-year-old raspberry starter; the wagyu beef with salt-fermented hairtail is a brilliantly inventive pairing.</p><h3>18. Fu 1015</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> 1015 Yuyuan Road, Changning District</p><p>One of the Fu restaurant family, centered on high-end Shanghainese cooking. Adhering to the principle of "eating only what is in season," it combines old Shanghai flavors with refined technique. Set in a historic garden villa, the environment is elegant and nostalgic; the cooking is rich and savory with the right balance of salt and sweetness — a taste of home.</p><h3>19. Fu 1039</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> 1039 Yuyuan Road, Changning District</p><p>A modern Shanghainese restaurant at an accessible price point. Dishes build on tradition with creative touches; the flavors are authentic yet fresh. The setting is warm and comfortable — an excellent choice for refined but relaxed Shanghainese cooking.</p><h3>20. Fu 1088</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> 1088 Yuyuan Road, Changning District</p><p>Specializing in the rich, deeply savory Shanghainese style. Stir-fried crab roe with toast and old Shanghai smoked pomfret are among the refined Shanghainese signatures guests come back for — a taste of home. Set in a historic building with a nostalgic, refined atmosphere.</p><h3>21. Da Dong (flagship)</h3><p><strong>Cuisine:</strong> Fashionable Chinese <strong>Address:</strong> Huangpu District</p><p>Newly awarded one star in 2025. The signature roast duck uses Beijing ducks — available in a 45-day force-fed duck or a 22-day young duckling option — yielding crackling skin and tender flesh. The chef carves at the table, slicing the caramelized duck skin into thin pieces with ceremony and precision. Braised sea cucumber in scallion sauce is soft and fragrant, richly flavored with scallion — not to be missed.</p><h3>22. San Yue Zui Huaiyang Jing''an (newly starred)</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> 5th floor, Yueyang Plaza, West Nanjing Road, Jing''an District</p><p>Newly awarded one star in 2026, created by Huaiyang cuisine heritage master Chef Zhou Xiaoyan. The signature "three-nested duck" (san tao ya) with shark''s fin debones mallard duck, free-range chicken, and squab and nests them inside each other, concentrating layer upon layer of savory depth. The top-broth clear-braised lion''s head is made entirely from hand-chopped pork, yielding a silky, melting texture. The Huaiyang stir-fried soft eel uses live eel back meat, blanched tableside to release the aroma of spring chives.</p><h3>23. Il Ristorante — Niko Romito</h3><p><strong>Cuisine:</strong> Italian <strong>Address:</strong> 47th floor, The Bulgari Hotel Shanghai, Jing''an District</p><p>Led by celebrated Italian chef Niko Romito with sweeping high-rise city views. The menu is seasonal while honoring tradition; the hand-made pasta selection is extensive. Recommended: fettuccine with lobster. The dessert of ricotta ice cream is smooth and richly fragrant. A consecutive Michelin one-star for multiple years — one of Shanghai''s top Italian restaurants.</p><h3>24. Jin Xuan</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> The Ritz-Carlton Shanghai Pudong, Pudong New Area</p><p>Located in the Ritz-Carlton Pudong, specializing in refined Cantonese cooking. Ingredients are of premium quality; the technique follows Cantonese tradition with emphasis on the natural flavor of each ingredient. A luxurious setting with panoramic Pudong skyline views — suited to high-end entertaining.</p><h3>25. Lao Zheng Xing</h3><p><strong>Cuisine:</strong> Shanghainese (traditional) <strong>Address:</strong> 556 Fuzhou Road, Huangpu District</p><p>Shanghai''s most historically significant Shanghainese restaurant, founded in 1862 and the originator of many classic dishes. Signature deep-fried shrimp is cooked with perfect timing — the shell is crispy, the meat springy, dressed in the characteristic sweet Shanghainese sauce. Marinated yellow croaker fillet is fresh and silky. The definitive address for authentic old-style Shanghai cuisine.</p><h3>26. Le Comptoir de Pierre Gagnaire</h3><p><strong>Cuisine:</strong> French <strong>Address:</strong> Capella Shanghai, Jian Ye Li, Xuhui District</p><p>Led by celebrated French chef Pierre Gagnaire, set within the shikumen lane architecture of Jian Ye Li. Dishes use a classical French foundation as the canvas for the chef''s signature creativity. The setting blends Shanghainese heritage with French elegance — a singular address for high-end French dining.</p><h3>27. Lei Garden Pudong</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Pudong New Area</p><p>The Pudong location of Lei Garden, specializing in traditional Cantonese cooking. Known for consistently high-quality output; signatures such as the crispy roasted pork belly and lobster soup with puffed rice are widely praised. The dim sum selection is extensive — a reliable choice for business dining and family gatherings.</p><h3>28. Lei Garden Xuhui</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Xuhui District</p><p>The Xuhui location of Lei Garden, with the same traditional Cantonese focus as the Pudong branch. Dishes emphasize fresh ingredients and precise heat; roasted meats, seafood, and braised dishes all hold a high standard. The environment is elegant and service professional — a trusted choice for classic Cantonese.</p><h3>29. Ling Long</h3><p><strong>Cuisine:</strong> Innovative <strong>Address:</strong> Ground floor, Waldorf Astoria Shanghai on the Bund, Huangpu District</p><p>Set within a century-old building, the interior uses a contemporary Chinese aesthetic in red and black. Only tasting menus are served; young chef Jason applies Western cooking techniques to Chinese seasoning. Signature dish "Oyster and Beef" uses Shandong wagyu, first deep-fried then roasted, paired with a house-made oyster sauce from Fujian oysters — a riff on classic oyster beef. The food-and-wine pairing program is witty and well-considered.</p><h3>30. Lu Cai Huangpu</h3><p><strong>Cuisine:</strong> Shandong <strong>Address:</strong> Huangpu District</p><p>A high-end Shandong cuisine restaurant, celebrated for dishes such as sea cucumber braised in scallion sauce and red-braised pork intestine. Much of the produce is sourced directly from Shandong; technique follows the Shandong tradition with emphasis on balance of heat and seasoning. The cooking is bold and substantial, showcasing the character of northern Chinese cuisine in its most refined form.</p><h3>31. Maison Lameloise</h3><p><strong>Cuisine:</strong> Contemporary French <strong>Address:</strong> 68th floor, Shanghai Tower, Pudong New Area</p><p>The first Asian outpost of a French Michelin dynasty, perched on the 68th floor of Shanghai Tower with 180-degree panoramic Bund views. The new chef trained under Eric Pras at the French flagship and maintains the same culinary style. Some dishes incorporate Chinese local ingredients into classic French preparations. The bread selection is exceptional; the wine list includes notable Burgundy bottles.</p><h3>32. Yu Bund (Zhongshan Dong Er Road)</h3><p><strong>Cuisine:</strong> Fujian <strong>Address:</strong> BFC Bund Finance Center, Huangpu District</p><p>The first Fujian cuisine restaurant on the Chinese mainland to receive a Michelin star. Signature Buddha Jumps Over the Wall combines sea cucumber, abalone, and other precious ingredients in a slow-braised broth of remarkable richness and depth. Red crab glutinous rice cake and chicken broth with razor clams are also outstanding. The restaurant has Bund river views, so the dining experience is doubly rewarding.</p><h3>33. Ming Ge Minhang</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Cordis Shanghai Hongqiao, Minhang District</p><p>Located in the Cordis Hotel Hongqiao, specializing in refined Cantonese cooking. Ingredient sourcing is careful; technique upholds the Cantonese tradition. From classic dim sum to seafood banquet dishes, the standard is consistently high. The setting is elegant and spacious — suitable for business entertaining and formal gatherings.</p><h3>34. Lu Yuan Changning</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> 1, Lane 119, Xinhua Road, Changning District</p><p>A high-end creative Huaiyang cuisine restaurant hidden in a century-old garden villa. Celebrated for its "four must-order dishes and eight signature dishes," the menu blends traditional Huaiyang technique with a contemporary aesthetic. Precise knife work and careful heat control produce a clean, fresh, subtly sweet quality that has made it a favorite among Shanghai''s serious food lovers.</p><h3>35. Lu Yuan Pudong</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> Pudong New Area</p><p>The Pudong location of Lu Yuan, carrying forward the brand''s Huaiyang essence. The menu centers on Jiangnan flavors, with careful attention to seasonal ingredients — clean, fresh, and elegantly presented. A reliable choice for refined Huaiyang cooking.</p><h3>36. Narisawa</h3><p><strong>Cuisine:</strong> Innovative <strong>Address:</strong> Jing''an District</p><p>Newly awarded one star in 2025, overseen by Japanese chef Narisawa. The menu changes with the seasons and relies heavily on local Chinese ingredients, weaving together Eastern and Western cooking technique with great finesse. The signature forest bread is fermented tableside and baked at high heat in a stone pot; the garnishes rotate seasonally through white tea, citrus, and other fresh flavors. An open kitchen with counter seating allows close interaction.</p><h3>37. Obscura</h3><p><strong>Cuisine:</strong> Innovative <strong>Address:</strong> Jing''an District</p><p>East-meets-West fusion at its most experimental and artistic. The chef brings traditional Chinese ingredients into contact with Western technique, producing flavor experiences that are genuinely surprising. Only tasting menus are offered; the courses unfold in chapters, like a narrative told through taste. The environment is quiet and intriguing — suited to diners seeking a novel experience.</p><h3>38. Eastern Panorama Feast</h3><p><strong>Cuisine:</strong> Fusion <strong>Address:</strong> Huangpu District</p><p>Fusing the best of Eastern and Western cooking to create refined, inventive dishes. Seasonal and ingredient-led; plated with artistry. The setting is elegant and the atmosphere intimate — an excellent choice for exploring creative Chinese cuisine.</p><h3>39. Ren He Guan Xuhui</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Xuhui District</p><p>Specializing in refined Shanghainese cooking — rich with the characteristic savory-sweet balance. The signature dishes follow Shanghai''s traditional flavors with careful attention to freshness and cooking timing. The environment is warm and unpretentious, and the prices are accessible — a fine choice for genuine everyday Shanghai home cooking.</p><h3>40. Jia Quan Qi Fu</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Jing''an District</p><p>A high-end Cantonese restaurant built on traditional technique. Premium ingredients throughout; seafood, roasted meats, and braised dishes all of high quality. The setting is elegant, the atmosphere rich — suited to business entertaining and formal dinners. A reliable choice for classic Cantonese.</p><h3>41. Sheng Yong Xing Huangpu</h3><p><strong>Cuisine:</strong> Beijing <strong>Address:</strong> 5th floor, Bund Number 5, 20 Guangdong Road, Huangpu District</p><p>Set in Bund Number 5 with luminous river views and a romantic atmosphere. Signature Peking duck uses 45-day Beijing force-fed ducks roasted over jujube wood — the skin is crispy, the meat tender, rich without being heavy. A large cellar overseen by a sommelier offers a wine list with pairing guidance. The destination for Beijing cuisine in Shanghai.</p><h3>42. Jing Xuan</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Huangpu District</p><p>Newly awarded one star in 2025, with consulting executive chef Lu Yiming and a kitchen team entirely from Guangdong. The menu spans classic Cantonese cooking to Chaoshan specialties. Fiddler crab roe and scallop dumpling has a translucent skin and golden, intensely savory filling. Stuffed deep-fried fresh crab shell and traditional ji zi ge zha are produced in limited quantities — booking in advance is strongly recommended.</p><h3>43. Vivant by Johnny Pham (newly starred)</h3><p><strong>Cuisine:</strong> French <strong>Address:</strong> 279 Beihai Road, Huangpu District</p><p>Newly awarded one star in 2026, set in the century-old Far East Hotel. Vietnamese-French chef Johnny Pham bridges his Vietnamese heritage with the culinary techniques of Lyon. Signature sea urchin risotto contains no cream — the fat of horse-urchin emulsifies naturally to create the texture; the whole blue lobster is charcoal-grilled to a just-set state, the meat springy and supremely fresh. The food-and-wine program is carefully considered.</p><h3>44. Wu You Xian</h3><p><strong>Cuisine:</strong> Dim sum (soup dumplings) <strong>Address:</strong> Pudong New Area</p><p>Shanghai''s first Michelin-starred restaurant dedicated to soup dumplings. The dumplings are wrapped to order; the skin is impossibly fine, and the filling is made fresh every day. The chefs separate the crab into roe, coral, and meat for multiple filling varieties; the pure crab soup dumpling is the most popular. "The Feeling of Three Crabs" lets you taste three variations in one order; the wild shepherd''s purse seasonal dumpling is also worth trying.</p><h3>45. Xin Rong Ji South Nanjing Road</h3><p><strong>Cuisine:</strong> Taizhou <strong>Address:</strong> 688 West Nanjing Road, Jing''an District</p><p>The leading name in Taizhou cuisine, with a seafood counter at the entrance where guests can select their own fresh produce. Signature golden crispy hairtail is crunchy outside and tender within; sand garlic bean vermicelli is savory and aromatic; home-style braised yellow croaker is a timeless classic. Seasonal, well-sourced, true to the natural flavor of every ingredient — the first choice for Zhejiang coastal food.</p><h3>46. Yi Long Ge</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> The Peninsula Shanghai, Huangpu District</p><p>Set within the Peninsula Hotel, the environment is luxurious and refined. Specializing in high-end Cantonese cooking with premium ingredients and masterful technique. From classic dim sum to seafood banquet dishes, the standard is consistently impeccable. Huangpu River views make it suitable for formal entertaining and special occasions.</p><h3>47. Yong Fu Hongkou</h3><p><strong>Cuisine:</strong> Ningbo <strong>Address:</strong> Hongkou District</p><p>The Hongkou location of Yong Fu, carrying forward the brand''s Ningbo essence. The kitchen centers on East China Sea seafood; dishes preserve the natural flavor of the ingredients. Signature white crab roe stir-fried with rice cake is outstanding; the signature "eighteen cuts" drunken crab is strongly seasonal. The destination for authentic Ningbo flavors.</p><h3>48. Yong Fu Huangpu</h3><p><strong>Cuisine:</strong> Ningbo <strong>Address:</strong> North Building, Jing Jiang Hotel, South Maoming Road, Huangpu District</p><p>A high-end Ningbo restaurant in the historic north building of the Jing Jiang Hotel. Signature fresh live large yellow croaker is cooked to order, the flesh fine-grained and intensely savory; the crab roe series is highly seasonal and delicious. A bowl of Ningbo glutinous rice balls to finish — sweetly satisfying without being cloying. Elegant environment; professional service.</p><h3>49. Yong Yi Ting</h3><p><strong>Cuisine:</strong> Jiangnan (Jiangsu and Zhejiang) <strong>Address:</strong> Mandarin Oriental Pudong, Pudong New Area</p><p>Set within the Mandarin Oriental Pudong, centered on the flavors of the Yangtze River Delta region. Dishes draw on the best of both Jiangsu and Zhejiang culinary traditions, with careful attention to seasonal ingredients — light and fresh in spring and summer, rich and deep in autumn and winter. Refined, comfortable, and considered.</p><h3>50. Yue Hai Tang</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Minhang District</p><p>Refined Cantonese cooking that balances tradition with contemporary touches. The kitchen team is rigorous about ingredient quality; roasted meats, seafood, and dim sum all maintain a high standard. The setting is elegant — suited to business dining and family gatherings.</p><h3>51. Zhou She Minhang</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Minhang District</p><p>Newly awarded one star in 2025, located near the airport and train stations — ideal for business entertaining. The menu follows Shanghainese technique while also drawing from Cantonese and Huaiyang cooking. Recommended: Sichuan pepper-braised squab, the young bird slowly marinated in an aged master brine until tender and deeply flavorful; garlic shoot stir-fried with eel strips requires precise knife work and captures the full fresh savory quality of the eel.</p><h2>Four: Bib Gourmand Restaurants (Shanghai — 33 restaurants)</h2><h3>52. Gucheng Yan (newly listed)</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection. Specializing in Jiangnan-style noodles — a rich, savory broth and a generous selection of toppings, authentically presenting the everyday noodle culture of the Jiangnan region at an accessible price.</p><h3>53. Lao Di Fang Noodle Shop</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Shanghai</p><p>A thirty-year-old institution that recently moved and reopened — the neighborhood "old place" where locals come for traditional home-style noodles. The toppings are stir-fried fresh and change with the season. Recommended: the pickled green vegetable and dried squid noodle — the lightly brined greens and squid stir together to produce a crisp, bright, clean flavor. Pair with braised pork wrapped in tofu skin or red-braised pork for extra satisfaction. Everything is made to order, so patience is rewarded.</p><h3>54. Rong Family Yellow Croaker Noodles Jing''an</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Jing''an District</p><p>Famous for yellow croaker noodles: the broth is made from fresh yellow croaker and has an intense, clean savoriness. The fish is tender with no off flavors; the noodles are springy and soak up the broth beautifully. Accessible pricing makes this one of the most popular addresses for experiencing Shanghai noodle culture.</p><h3>55. Ho Hung Kee</h3><p><strong>Cuisine:</strong> Congee and noodles <strong>Address:</strong> Shanghai</p><p>Known for both congee and noodles. The signature premium congee is richly garnished and the congee base is silky smooth. The wonton noodle soup has a sweet, fresh broth; wontons have thin skin and fresh filling. Good value, consistent quality — a convenient introduction to Cantonese-style congee and noodle culture.</p><h3>56. Lan Xin Jinxian Road</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Jinxian Road, Huangpu District</p><p>A Shanghainese home-cooking restaurant hidden in the lanes of Jinxian Road — plain in appearance, long in queues, thanks to flavors that are deeply authentic. Signature red-braised pork belly is dark, glossy, rich, and non-greasy; deep-fried shrimp has a crispy shell and sweet meat. An essential stop for the market flavor of old Shanghai.</p><h3>57. Chun</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Shanghai</p><p>A small Shanghainese restaurant — cooking that carries the characteristic rich, savory-sweet balance of the tradition. Simple, warm, affordable. Signature dishes follow Shanghai''s home-cooking flavors — a high-value choice for authentic Shanghainese.</p><h3>58. Cong Cai Guan</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Shanghai</p><p>The owner, now past seventy, returned to Shanghai after retiring because of his love of cooking and opened this shop. Specializing in Shanghai dishes with a personal touch — smoked fish made with devil ray; fish liver pate with ginger and vinegar. Signature river shrimp stir-fried with shrimp roe pairs the shrimp with intensely flavorful shrimp roe for maximum savory depth. Chinese furniture paired with artworks makes the interior comfortable and distinctive.</p><h3>59. Polux</h3><p><strong>Cuisine:</strong> French <strong>Address:</strong> Xintiandi, Huangpu District</p><p>A casual French home-cooking restaurant from Ultraviolet chef Paul Pairet, set in a freestanding historical villa in Xintiandi. Dishes are grounded in classic French family cooking; the signature duck confit has crispy skin and tender meat. Relaxed, unhurried — ideal for a leisurely lunch. An enjoyable and accessible entry point into French cuisine.</p><h3>60. Rong Xiao Guan Huangpu</h3><p><strong>Cuisine:</strong> Taizhou <strong>Address:</strong> Huangpu District</p><p>The accessible-price sibling brand of Xin Rong Ji, bringing Taizhou flavors to a more affordable setting. Fresh seafood produce; dishes stay true to the natural flavor of the ingredients. Classic dishes such as home-style braised yellow croaker and sand garlic bean vermicelli maintain the brand''s standards at a lower price point.</p><h3>61. Yangzhou Restaurant Huangpu</h3><p><strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> Huangpu District</p><p>A long-established Huaiyang restaurant, celebrated for classic flavors. Signature lion''s head meatball is light and porous, melting on the tongue; da zhu gan si (finely shredded pressed tofu in broth) requires precise knife work and has a rich, savory broth. A fine, affordable address for traditional Huaiyang cooking.</p><h3>62. Mao Long</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Shanghai</p><p>An old-style Shanghainese restaurant known for the rich, deeply sauced character of the traditional style. Generous portions, honest flavors; red-braised pork belly and soy-braised duck are the dishes guests keep coming back for. Simple surroundings — the focus is on the food.</p><h3>63. Qiao Ai Lai Lai Xiao Long Huangpu</h3><p><strong>Cuisine:</strong> Dim sum <strong>Address:</strong> Huangpu District</p><p>A dim sum shop centered on soup dumplings: thin skin, fresh filling, plenty of soup. Alongside the classic fresh pork variety, seasonal crab roe soup dumplings are exceptional when available. Affordable and accessible — a quick way to experience Shanghai''s dim sum culture.</p><h3>64. Jing Mei Wuxi Noodle House Yanping Road</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Yanping Road, Jing''an District</p><p>Specializing in Wuxi-style noodles — a sweet, savory broth and rich toppings. The signature spare rib noodle has fall-off-the-bone ribs deeply infused with flavor; the noodles are smooth. Good value — an excellent stop for experiencing the noodle culture of Jiangnan.</p><h3>65. Xiao Tao Noodle Shop</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Shanghai</p><p>A neighborhood noodle shop celebrated for its freshly stir-fried toppings. A wide choice of toppings, authentic flavors, generous portions. A simple, honest address for everyday Shanghai noodle culture.</p><h3>66. Lin Hu Vegetarian</h3><p><strong>Cuisine:</strong> Vegetarian <strong>Address:</strong> Shanghai</p><p>Refined vegetarian food at accessible prices; the menu focuses on seasonal ingredients and nutritional balance. A clean, pleasant environment suited to health-conscious diners. A high-value introduction to Chinese vegetarian cuisine.</p><h3>67. Gui Xi (newly listed)</h3><p><strong>Cuisine:</strong> Teochew (Chaozhou) <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection. Specializing in traditional Teochew cooking — braised dishes, seafood, and other classic Teochew preparations done authentically at an accessible price. A friendly introduction to everyday Teochew food.</p><h3>68. One Five Seven (newly listed)</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> 1398 Kaixuan Road, Changning District, IM Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection. Refined, thoughtful dishes that blend tradition and innovation — accessible prices and home-cooking character make this a fresh new choice for experiencing Shanghai''s local food culture.</p><h3>69. Ou Yue Zun Xian (newly listed)</h3><p><strong>Cuisine:</strong> Zhejiang <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection, specializing in Wenzhou-style Zhejiang cooking. Centered on mountain and sea ingredients; dishes prioritize the natural flavor of the produce, delivering layers of savoriness. Accessible pricing — an affordable introduction to the coastal flavors of southern Zhejiang.</p><h3>70. Yi Cai Jing''an</h3><p><strong>Cuisine:</strong> Jiangnan (Jiangsu and Zhejiang) <strong>Address:</strong> Jing''an District</p><p>Jiangnan-focused cooking — clean, fresh, and lightly sweet with a strong emphasis on seasonal produce. Simple technique lets the ingredients speak; a gentle, accessible version of everyday Jiangnan home cooking. Comfortable and unassuming — good for a casual meal.</p><h3>71. Yu Du Lao Wei Noodles</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Huangpu District</p><p>A noodle restaurant known for seafood toppings — a rich broth with generous, fresh seafood. All toppings are freshly stir-fried; the flavor is intensely savory. A good-value address that combines Shanghai noodle culture with the freshness of the sea.</p><h3>72. Yu Ge Zhanjiang Jing''an</h3><p><strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Jing''an District</p><p>Specializing in Zhanjiang-style Cantonese cooking, with seafood as the focus. Dishes emphasize the freshness and natural flavor of the produce; blanching and steaming preserve the sweetness of the seafood. Accessible pricing — an affordable entry point into Cantonese-style seafood.</p><h3>73. Yun He Noodle House Huangpu</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Huangpu District</p><p>Known for freshly stir-fried toppings — a wide choice and authentic flavors. Rich broth; springy noodles. Simple surroundings focused entirely on value and taste — a reliable choice for Shanghai noodle culture.</p><h3>74. He Shan Noodle Family (newly listed)</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection, specializing in refined noodles. A carefully prepared broth with rich toppings at accessible prices — a fresh new entry into everyday Shanghai food culture.</p><h3>75. Yong Fu Xiao Xian Pudong</h3><p><strong>Cuisine:</strong> Ningbo <strong>Address:</strong> Pudong New Area</p><p>The affordable sibling brand of Yong Fu, bringing Ningbo flavors to a more accessible price point. Signature white crab roe stir-fried with rice cake is outstanding; the signature "eighteen cuts" drunken crab is strongly seasonal. A high-value introduction to Ningbo cooking.</p><h3>76. Mi Thai</h3><p><strong>Cuisine:</strong> Thai <strong>Address:</strong> Anfu Road, Xuhui District</p><p>A long-established Thai restaurant on Anfu Road, included in the Bib Gourmand selection for multiple consecutive years. Committed to the traditional central Thai culinary tradition — signature tom yum soup achieves a perfect sour-spicy balance; crispy shrimp cake is crunchy outside and fresh inside. Authentic Thai food at accessible prices — a popular destination for a different kind of flavor.</p><h3>77. Green Wave Gallery (Lu Bo Lang)</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> 115 Yuyuan Road, Huangpu District</p><p>Set beside the nine-turn bridge at the Yu Garden, on a site that has been a teahouse since the Ming dynasty — over four hundred years of history. Known for refined Shanghainese dim sum and dishes; signature osmanthus pull cake and brow pastries are delicate and authentic. Having hosted dignitaries from many countries, this is a landmark restaurant for experiencing Shanghai''s traditional food culture.</p><h3>78. Tan (newly listed)</h3><p><strong>Cuisine:</strong> Sichuan <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection. Authentic Sichuan cooking — the classic numbing-spicy-fresh character is achieved with high-quality Sichuan peppercorns and chilies. Accessible pricing — an affordable new choice for genuine Sichuan flavors.</p><h3>79. Nanxiang Steamed Bun Restaurant</h3><p><strong>Cuisine:</strong> Dim sum <strong>Address:</strong> 87 Yuyuan Road, Huangpu District</p><p>A celebrated xiaolongbao institution with roots in the Guangxu reign of the Qing dynasty, located in the City God Temple precinct. The queue is long year-round. Signature crab roe and fresh pork xiaolongbao have thin, delicate skin and a generous filling — bite in and a rush of golden crab oil follows. A pilgrimage stop for traditional Shanghai dim sum.</p><h3>80. Hao Sheng Restaurant</h3><p><strong>Cuisine:</strong> Shanghainese <strong>Address:</strong> Shanghai</p><p>A classic Shanghainese restaurant known for the deeply rich, savory-sweet character of traditional Shanghai home cooking. Generous portions, honest flavors; red-braised pork belly and soy-braised duck are the signature dishes guests return for. Unpretentious surroundings — the food is the point.</p><h3>81. Gong De Lin South Nanjing Road</h3><p><strong>Cuisine:</strong> Vegetarian <strong>Address:</strong> 441 West Nanjing Road, Huangpu District</p><p>A century-old vegetarian institution founded in 1922, with its vegetarian preparation techniques certified as a national intangible cultural heritage. Signature mock crab roe uses potato and carrot to mimic the color and flavor of real crab roe with remarkable fidelity. Mock duck, crab roe tofu, and other favorites have delighted generations of diners. The classic address for Chinese vegetarian culture.</p><h3>82. Da Hu Chun Sichuan Middle Road</h3><p><strong>Cuisine:</strong> Dim sum <strong>Address:</strong> 136 Sichuan Middle Road, Huangpu District</p><p>One of Shanghai''s most celebrated pan-fried dumpling (sheng jian) institutions. The bun skin is of the right thickness; the base is fried to a glowing golden brown; the filling is substantial and juicy. A bite releases fragrance from all sides. The iconic address for experiencing Shanghai''s traditional morning food culture.</p><h3>83. Ning Hai Shi Fu (newly listed)</h3><p><strong>Cuisine:</strong> Ningbo <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection, specializing in authentic Ningbo cooking. Centered on East China Sea seafood; dishes are simply prepared to preserve the natural flavor of the ingredients. Accessible pricing — an affordable introduction to everyday Ningbo home cooking.</p><h3>84. A Yong Noodle Shop Dongshu Fang Road (newly listed)</h3><p><strong>Cuisine:</strong> Noodles <strong>Address:</strong> Shanghai</p><p>Newly listed in the 2026 Bib Gourmand selection, specializing in Jiangnan-style noodles. Fresh-stir-fried toppings in a wide selection; rich broth; springy noodles. An authentic, affordable introduction to the everyday noodle culture of Jiangnan.</p>',
  '[]'::jsonb,
  6,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
