INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'suzhou_coffee_top10',
  'suzhou',
  'Suzhou Independent Coffee Guide · TOP 10',
  '苏州独立咖啡体验指南 · TOP 10',
  'A curated selection of ten independent specialty cafes in Suzhou, chosen for foreign visitors.',
  '☕',
  NULL,
  ARRAY[]::TEXT[],
  '<h2>1. Title Coffee</h2><p>Suzhou''s benchmark specialty coffee shop, run by Ms. Ma, a dedicated coffee enthusiast. All beans are roasted in-house, sourced from Ethiopia, Kenya, Panama, and other origins. The signature Sidama Huakui pour-over delivers passionfruit and rose aromas, with three distinct flavor profiles depending on whether served hot, iced, or at a midpoint temperature. Single Origin Espresso latte and cappuccino are great entry points. Whole beans and brewing equipment are available to buy; no food menu. The space is a minimalist black-and-white two-level interior — the entrance is understated, so keep an eye out.</p><p><strong>Address:</strong> 74 Pingqiao Zhi Street, Gusu District</p><p><strong>Why go:</strong> Widely regarded by Suzhou''s coffee community as the top all-round performer. Baristas are professional and happy to chat — the first choice for a serious specialty coffee experience.</p><h2>2. Sparrow Coffee</h2><p>One of Suzhou''s "Big Three" coffee shops, tucked inside a white-walled, grey-tiled bungalow on the small plaza at the entrance to Wulong Tang on Shiquan Street. Owner Huazi trained at coffee processing facilities in Yunnan. Six pour-over single-origins are offered, all roasted in-house, including Ethiopia, Burundi, and Colombia. The signature Yirgacheffe washed Grade 1 weaves jasmine and gentle citrus together beautifully. The Dirty — espresso over cold milk — is dine-in only, rich and layered. No food menu; the palette is black, white, and grey. The small square outside is perfect for drinking in the open air.</p><p><strong>Address:</strong> 683 Shiquan Street, Gusu District (next to Nanlin Hotel bus stop)</p><p><strong>Why go:</strong> One of Suzhou''s defining independent coffee brands — strong in-house roasting, a generous pour-over lineup, and an outdoor terrace on the plaza.</p><h2>3. Roasting Room</h2><p>Founded by Taiwanese barista Kevin, who holds CQI Q-Grader certification and has judged multiple coffee competitions. The focus is in-house roasted single-origin beans. Standouts include the Panama Geisha Zhanwang (natural process, grape and dark chocolate notes) and the Indonesia Mandheling Grade 1 (herbal cream aromas). The "Spring and Summer" espresso blend is fruit-forward and accessible for newcomers. Beans are available to take away — buy beans and get a complimentary cup. The shop is compact, with a mission to promote specialty coffee culture. Closed Mondays.</p><p><strong>Address:</strong> Unit 8, Building 12, Dushi Huayuan, Xingdu Street, Suzhou Industrial Park (near Xinghai Swimming Centre)</p><p><strong>Why go:</strong> A professional-grade roasting workshop with a Q-Grader-certified owner. Outstanding Geisha quality — ideal for coffee enthusiasts.</p><h2>4. Matrix Coffee</h2><p>Founded by three science graduates who approach coffee with methodical precision — their slogan is "The Coffee Science." Located in the basement of Eslite Life, with a striking white-and-red storefront. The menu is pure coffee: eight pour-over options covering Yirgacheffe, Mandheling, and Nicaragua Emerald (clean and bright with fruit notes). The seasonal salted cheese iced Americano — a salty cheese foam over Americano — is layered and inventive. Yunnan Pu''er coffee flower honey is also sold in-store. No food menu; polished commercial operation.</p><p><strong>Address:</strong> Unit B119, Basement Level 1, Eslite Life, 8 Yuelang Street, Suzhou Industrial Park</p><p><strong>Why go:</strong> Coffee made with scientific rigor, inside Eslite bookstore — easy to combine with browsing. Seasonal specials show real creativity.</p><h2>5. Energy Coffee</h2><p>Open since 2013, one of Suzhou''s earliest specialty cafes — tucked inside a lane in the Pingjiang Road historic district and a defining example of the "alley cafe" style. The owner also runs a coffee agency business, and pour-over standards are consistently high. The signature natural-process Yirgacheffe Aricha Grade 1 offers a complex bouquet of apricot blossom, nuts, and cinnamon, with lively yet gentle citrus acidity. Geisha and Mandheling are also available. The shop is tiny — a blackboard with witty slogans, black-and-white decor, and limited seating.</p><p><strong>Address:</strong> Near 60-2 Xuanqiao Lane, Pingjiang Road, Gusu District</p><p><strong>Why go:</strong> A veteran of Suzhou''s specialty coffee scene. Finding it in the depths of a Pingjiang Road lane is half the fun — a perfect stop while exploring the old street.</p><h2>6. 12 Hours Coffee</h2><p>Open since 2018, one of Suzhou''s rare "coffee plus art exhibition" hybrid spaces. The owner Wang Chao keeps half the floor dedicated to small exhibitions and product launches, so the setup changes with each theme — every visit feels fresh. Coffee centers on the classics; pour-over beans rotate weekly (ask the staff), with natural-process Yirgacheffe on permanent rotation (fruit-forward, with nuts and cinnamon, gentle acidity). The matcha happiness panna cotta is the dessert to order. Minimalist industrial interiors in black, white, and grey, with a power outlet at every seat.</p><p><strong>Address:</strong> 16 Ximei Lane, Gusu District (next to the Conference Centre)</p><p><strong>Why go:</strong> Coffee and contemporary art under one roof, with a strong design sensibility — a natural fit for art lovers and remote workers alike.</p><h2>7. Tommy Coffee</h2><p>Founded in 2018 by Tommy, formerly a barista at C-Point Cafe. The aesthetic is American retro-industrial: exposed brick, black lacquer glass doors, and recessed outdoor seating that adds a design edge. No pour-over on offer — the menu centers on Single Origin Espresso. The signature Dirty, with espresso layered over cold milk, is well-defined and satisfying. Latte is smooth, Americano is clean, and the affogato has its following too. The space is generous with warm lighting.</p><p><strong>Address:</strong> Unit A101, Lan Cultural and Creative Industry Park, 63 Renmin Road, Gusu District</p><p><strong>Why go:</strong> A standout American retro aesthetic and excellent Dirty. The Lan Cultural Park next door is worth a wander.</p><h2>8. Antidote Cafe and Bar</h2><p>The most distinctive cafe on Shiquan Street — coffee by day, cocktail bar by night. The Jiangnan grey-tile cottage exterior clashes brilliantly with the hard-edged industrial interior: black throughout, metal accents, a strong rock-and-roll energy. A Slayer Steam espresso machine anchors the bar, with a varied espresso menu including Single Origin Espresso options. The signature "Antidote" coffee comes served in a porter glass bottle — instantly recognizable. A pour-over bar with counter seating lets you watch every step of the brew. The second floor becomes a cocktail bar after dark.</p><p><strong>Address:</strong> 726-1 Shiquan Street, Gusu District</p><p><strong>Why go:</strong> Dual coffee-and-bar operation, an unmistakable industrial rock identity, and a Slayer espresso machine. Works equally well in daylight or after midnight.</p><h2>9. Han Xiang Hui She · Sign Language Cafe</h2><p>Suzhou''s first sign-language cafe — part social enterprise, part cultural exchange. Set along the Pingjiang River with canal views from the window. Staff are deaf and communicate with customers through sign language and writing boards — an experience that is both unique and genuinely warm. Inside, you can listen to Suzhou pingtan (a traditional storytelling-and-singing art; 38 RMB for two pieces), and browse intangible heritage handcraft demonstrations such as leaf carving and sugar figurine art. Coffee is straightforward espresso-based, alongside Suzhou-style tea drinks. Handicrafts made by artisans with disabilities are available to purchase.</p><p><strong>Address:</strong> 37 Pingjiang Road, Gusu District</p><p><strong>Why go:</strong> An experience found nowhere else — sign language service, pingtan performance, intangible heritage craft, and coffee all in one room. One of the most human and memorable stops in Suzhou for foreign visitors.</p><h2>10. Fein Coffee</h2><p>A neighborhood cafe with a distinctly Suzhou flavor. The signature osmanthus latte uses osmanthus blossoms from Guangfu town, blending floral and milky notes into something that tastes unmistakably like Jiangnan. The iced Americano is strong and excellent value. Light bites include a bacon cheese runny-egg burger. Average spend around 22 RMB — welcoming and unpretentious.</p><p><strong>Address:</strong> Unit 1-102, 35 Shishan Road, High-tech District (Shishan Culture Plaza)</p><p><strong>Why go:</strong> The osmanthus latte is one of a kind. Affordable prices, good light bites for breakfast or brunch, and a taste of Suzhou in a cup.</p>',
  '[]'::jsonb,
  0,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
