INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'suzhou_hanfu',
  'suzhou',
  'Suzhou Hanfu Rental Guide',
  '苏州汉服体验指南',
  'For: Foreign Visitors Last updated: June 2026',
  '👘',
  NULL,
  ARRAY[]::TEXT[],
  '<h2>Contents</h2><p>1. [Recommended Shops](#recommended-shops) 2. [Price Reference](#price-reference) 3. [Tips to Avoid Common Pitfalls](#tips-to-avoid-common-pitfalls) 4. [Best Photo Locations](#best-photo-locations) 5. [Tips for Foreign Visitors](#tips-for-foreign-visitors) 6. [Suggested Schedule](#suggested-schedule)</p><h2>Recommended Shops</h2><h3>1. Fen Dai San Qian Hanfu Experience Studio</h3><ul><li><strong>Address:</strong> C2 Building, Xiangmen City Wall, Gusu District, Suzhou</li><li><strong>Hours:</strong> 10:00–20:00</li><li><strong>Nearby attractions:</strong> Pingjiang Road, Shantang Street, Humble Administrator''s Garden</li><li><strong>Hanfu styles available:</strong> Tang dynasty, Song dynasty, Ming dynasty, Wei-Jin style, Warring States robe, Qing dynasty Han-style dress, and more</li><li><strong>Services:</strong> Professional hair and makeup, indoor scene photography, indoor and outdoor photo escort, and cultural experiences such as hairpin flower arrangement and lacquer fan painting</li></ul><p><strong>Why go:</strong> Recommended by multiple influencer bloggers, and ideally located next to Pingjiang Road. Wide range of costume styles and a professional styling team — perfect for visitors who want a one-stop "dress up and shoot" experience.</p><h3>2. Fu Sheng Xi Yue Hanfu Studio</h3><ul><li><strong>Address:</strong> 813 Changxu Road, Jinglu Street, Gusu District, Suzhou (north end of Shantang Street, near Chang Gate and Bai Juyi Pier)</li><li><strong>Nearby attractions:</strong> Shantang Street</li><li><strong>Hanfu styles available:</strong> Wei-Jin style, Warring States robe, horse-face skirt, qipao, new Chinese style, Tang-style dress, Qing dynasty Han-style dress</li><li><strong>Services:</strong> Professional hair and makeup by experienced stylists, professional photo escort, and cultural experiences such as hairpin flower arrangement and lacquer fan painting</li></ul><p><strong>Why go:</strong> Situated at the northern gateway to Shantang Street, built right along the river — the building itself looks like a watercolor painting. Especially rewarding if you rent in the late afternoon, since you can shoot both daytime and evening looks in a single outing. The red lanterns at night pair beautifully with hanfu.</p><h3>3. Ru Meng Ling Hanfu Experience Shop</h3><ul><li><strong>Address:</strong> Pingjiang Road Historic District (search "Ru Meng Ling Hanfu" on any map app)</li><li><strong>Price:</strong> Rental 198 RMB per set; deposit 500 RMB</li><li><strong>Return deadline:</strong> Before 22:00</li><li><strong>Services:</strong> Full-day costume rental, professional hair styling (dedicated hair stylists), makeup design</li><li><strong>Hanfu styles available:</strong> Tang-style dress, Ming dynasty hanfu, and more</li></ul><p><strong>Why go:</strong> Excellent value at 198 RMB for the full day. Located right in the heart of Pingjiang Road — once you''re dressed and styled, you can walk straight to Pingjiang Road, the Humble Administrator''s Garden, or Couple''s Garden to shoot. Reviews on local platforms highlight professional styling and patient service.</p><p><strong>Note:</strong> This shop is extremely popular. Some visitors have found that by the time they arrive at 09:00 the same-day queue is already full. Arrive early or book in advance.</p><h2>Price Reference</h2><h2>Basic hanfu rental (costume only)</h2><ul><li>Price: 60–120 RMB per day</li><li>Note: Smaller shops on the outskirts of Pingjiang Road, no makeup services</li></ul><h2>Costume + basic makeup</h2><ul><li>Price: 128–198 RMB per day</li><li>Note: Standard package at most shops</li></ul><h2>Costume + deluxe makeup</h2><ul><li>Price: 200–300 RMB per day</li><li>Note: Includes elaborate hairstyling and full makeup</li></ul><h2>Costume + makeup + photo escort</h2><ul><li>Price: 300–600+ RMB</li><li>Note: Includes raw files and professionally retouched photos</li></ul><h2>Premium or trending new styles</h2><ul><li>Price: 300+ RMB per day</li><li>Note: Varies by costume style</li></ul><h2>Tips to Avoid Common Pitfalls</h2><h3>1. Book in Advance</h3><ul><li>On weekends, public holidays, and during peak season (March–May, September–November), book 1–3 days ahead</li><li>Popular shops like Ru Meng Ling may have their same-day slots filled by 09:00</li><li>For Klook or Ctrip packages, book 3–7 days in advance</li></ul><h3>2. Deposits</h3><ul><li>Hanfu rentals typically require a deposit (200–1,000 RMB, varies by shop)</li><li>Keep your deposit receipt and confirm the return time and refund process before you leave</li><li>Shops with a larger storefront and strong reputation are generally more reliable</li></ul><h3>3. Hygiene</h3><ul><li>Hanfu sits against your skin — bring your own nude-colored strapless undergarments and leggings</li><li>Check whether the garments on display are hanging neatly and are free of stains</li><li>If you have sensitive skin, consider bringing your own base makeup products</li></ul><h3>4. Time Planning</h3><ul><li>Full hair and makeup takes about 1 to 1.5 hours</li><li>Set aside at least a half-day (3–4 hours) so you''re not rushing between sights</li><li>The earlier you rent, the more value you get — more time in costume means more time to shoot</li></ul><h3>5. Luggage Storage</h3><ul><li>You can store your everyday clothes and bags at the shop for free</li><li>Check the shop''s closing time and make sure to return before they shut</li></ul><h3>6. Hidden Costs</h3><ul><li>Before booking, confirm exactly what the package includes</li><li>The price gap between basic and deluxe makeup can be significant</li><li>Clarify upfront whether photo escort includes retouching and how many raw files are delivered</li></ul><h3>7. Weather</h3><ul><li>Light rain or overcast skies can actually create a beautiful, moody Jiangnan atmosphere</li><li>If bad weather hits, contact the shop early to reschedule</li></ul><h2>Best Photo Locations</h2><h2>Humble Administrator''s Garden</h2><ul><li>Best for: grand classical garden scenes, stately Ming dynasty styles</li><li>Admission: 80 RMB</li></ul><h2>Lingering Garden</h2><ul><li>Best for: refined and elegant settings, cool Song dynasty styles</li><li>Admission: 55 RMB</li></ul><h2>Couple''s Garden</h2><ul><li>Best for: romantic themes, fewer crowds and more tranquil</li><li>Admission: Around 25 RMB</li></ul><h2>Pingjiang Road</h2><ul><li>Best for: canal-town street photography, everyday Jiangnan life feel</li><li>Admission: Free</li></ul><h2>Shantang Street</h2><ul><li>Best for: evening red-lantern atmosphere</li><li>Admission: Free</li></ul><h2>Suzhou Museum</h2><ul><li>Best for: modern geometric architecture contrasted with classical dress</li><li>Admission: Free (reservation required)</li></ul><h2>Yi Garden</h2><ul><li>Best for: intimate and refined, a local favorite</li><li>Admission: Around 10 RMB</li></ul><h2>Canglang Pavilion</h2><ul><li>Best for: the distinctive double-corridor walkway</li><li>Admission: Around 20 RMB</li></ul><h2>Suggested Schedule</h2><p>``` 09:00  Arrive at the shop, choose your costume (30 minutes) 09:30  Hair and makeup begins (1–1.5 hours) 11:00  Styling complete, head to your shooting location 11:30–16:30  Shooting time (Pingjiang Road / classical gardens / Shantang Street, etc.) 17:00  Return to the shop, return costume, collect deposit refund ```</p><h2>Suggestions:</h2><ul><li>If you plan to visit the Humble Administrator''s Garden, choose a shop nearby — you can walk in within minutes of getting dressed</li><li>If you want evening shots, choose a shop in the Shantang Street area — renting in the late afternoon gives you the best value</li><li>If you''re on a budget, look at shops on the side streets off Pingjiang Road rather than the main strip — prices are noticeably lower</li></ul>',
  '[]'::jsonb,
  1,
  TRUE
) ON CONFLICT (id) DO UPDATE SET
  city_id = EXCLUDED.city_id,
  title_en = EXCLUDED.title_en,
  title_zh = EXCLUDED.title_zh,
