INSERT INTO city_guides (
  id, city_id, title_en, title_zh, subtitle, icon, badge,
  cover_images, body, meta_items, display_order, is_published
) VALUES (
  'suzhou_michelin',
  'suzhou',
  'Suzhou Michelin Guide Restaurants',
  '苏州米其林指南餐厅介绍文案',
  'This document introduces Michelin Guide-listed restaurants in Suzhou, written for foreign visitors.',
  '🍽',
  'Dining',
  ARRAY[]::TEXT[],
  '<h2>Michelin One-Star Restaurants</h2><h3>Pingjiang Song</h3><p><strong>Rating:</strong> Michelin One Star <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 54 Daru Lane, Gusu District, Suzhou <strong>Phone:</strong> +86 512 6610 9077 <strong>Hours:</strong> Confirm in advance (reservation strongly recommended) <strong>Average spend:</strong> 1,000–1,700 RMB per person (high-end; reservation required)</p><h2>Why go:</h2><p>Originally a five-courtyard Ming dynasty mansion, the restaurant fuses the elegance of traditional Suzhou architecture with classical garden aesthetics. The kitchen follows a strict "eat only what is in season" philosophy, honoring traditional Suzhou cuisine while incorporating modern cooking techniques. The signature dish pairs fresh shrimp marinated in Shaoxing lees sauce with caviar — the shrimp meat is plump and sweet, with amber-toned shrimp roe at the center and rich, layered complexity throughout. The duck broth with ham and Suzhou fox nuts is fragrant and deeply savory, with the soft, starchy fox nuts making it deeply memorable. Reservation essential.</p><h3>Dingshan Jiangyan</h3><p><strong>Rating:</strong> Michelin One Star <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 33rd Floor, East Hall, Tiancheng Times Business Plaza, 58 Qinglong Gang Road, Xiangcheng District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> 11:00–13:30, 17:00–20:30 <strong>Average spend:</strong> 450–500 RMB per person (mid-to-high end)</p><h2>Why go:</h2><p>Perched on the 33rd floor with panoramic views across Xiangcheng District. The dining room is decorated with Suzhou-style furniture and traditional Suzhou birdcages; private rooms are each themed around Suzhou culture. The menu offers a la carte, set menus, and a seasonal selection — advance reservation is required and dishes must be confirmed ahead of time. The signature Suzhou braised pork rice pot draws inspiration from Suzhou noodle traditions, blending glutinous and Wuchang rice and layering in potato, braised pork, and bamboo shoots, with house-made beef tendon and dried fish chili sauce that doubles the depth of flavor. Head chef Wang Jie won the 2025 Jiangsu Province Michelin Young Chef Award.</p><h3>Xiding Jiayan</h3><p><strong>Rating:</strong> Michelin One Star <strong>Cuisine:</strong> Northeastern Chinese <strong>Address:</strong> Unit 1, Block B, Xifu Li Commercial Plaza, 66 Chengtong Road, Xiangcheng District, Suzhou <strong>Phone:</strong> +86 512 8717 1888 <strong>Hours:</strong> Confirm in advance (reservation strongly recommended) <strong>Average spend:</strong> 600 RMB per person (high-end; set menu format)</p><h2>Why go:</h2><p>The first premium branch opened by a large dumpling chain, named "Family Banquet" to give guests the warmth and ease of eating at home. Most ingredients are sourced from the East China Sea, fresh and of excellent quality, prepared with distinctly Northeastern cooking methods. The signature Dalian sea urchin dumplings are outstanding — not to be missed. The menu also incorporates seasonal seafood such as marinated raw lobster and sea worm. Banquet packages centered on abalone or sea cucumber are available, well-suited to group dining.</p><h2>Bib Gourmand Restaurants</h2><h3>Sanxing Mutton Restaurant</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Jiangsu (Cangshu mutton) <strong>Address:</strong> 2411 Qiongling Road, Wuzhong District, Suzhou <strong>Phone:</strong> 0512-66242815 <strong>Hours:</strong> 09:30–20:30 <strong>Average spend:</strong> 80–120 RMB per person (mid-range)</p><h2>Why go:</h2><p>A long-established local institution, open for decades, offering whole-lamb banquet sets at multiple price points to suit every budget. Among the many dishes, the clear-braised mutton soup is unmissable. Made by slow-simmering lamb bones until the broth turns milky white, it is deeply savory and pure in flavor — wide-cut lamb ribs soak in the broth, absorbing the full richness of the meat and the soup. A side of soft lamb blood adds extra savoriness. The pure mutton dumplings have a translucent wrapper, juicy filling, and a satisfying depth of flavor.</p><h3>Yangzhou Yan · Quyuan</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Huaiyang <strong>Address:</strong> 2nd Floor, Building 8 Podium, Canal Platinum Bay Financial Plaza, 6 Lingyan Street, Huqiu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance (reservation recommended) <strong>Average spend:</strong> 120–200 RMB per person (mid-range)</p><h2>Why go:</h2><p>Bringing together two brands under the same group, the restaurant serves both Huaiyang dishes and traditional dim sum in one sitting. The dining room features glass wall lamps with a bamboo motif, carrying a distinctly Jiangnan atmosphere. The handmade crab roe soup dumplings are essential — steamed to order, with neatly pleated folds and a pure crab broth filling that is intensely savory. The morning tea session is especially good value. Private rooms are available for pre-arranged menus; ask the staff about seasonal specials not on the main menu.</p><h3>Sucheng Jiayan</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> Units 43–45, Phase 1, Li Gong Di, Suzhou Industrial Park <strong>Phone:</strong> 0512-62875088 / 0512-62953252 <strong>Hours:</strong> Confirm in advance (reservation recommended) <strong>Average spend:</strong> 100–200 RMB per person (mid-range)</p><h2>Why go:</h2><p>Set within the Jinji Lake scenic area, the restaurant has private rooms and an outdoor dining terrace where you can eat while watching the lake — a genuinely pleasant experience, though reservations are strongly advised. A la carte only, with a range of lightly seasoned Suzhou dishes at fair prices. The signature lion''s head meatball is hand-formed from mandarin fish and heritage pork, tender and springy, served in a clear, fragrant broth. Arriving at dusk to catch the sunset over Jinji Lake is highly recommended.</p><h3>Liujiayou Mengmei</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Dim sum (wonton) <strong>Address:</strong> 8 Pingqiao Zhi Street, Gusu District, Suzhou <strong>Phone:</strong> +86 139 5169 7276 <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 30–60 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>The owner is a kunqu opera actor, and the dining room is decorated with traditional opera motifs. The restaurant''s name is taken from the character Liu Mengmei, which the owner performed in The Peony Pavilion. The menu centers on hand-wrapped wontons in a variety of fillings — three-fresh, vegetarian, shrimp, and coriander-beef among them. The signature abalone wonton is filled with fresh abalone and pork, plump and juicy. The broth is made by simmering over a dozen ingredients together for a deeply savory result. Stinky tofu and pork chops are also on offer. The atmosphere is intimate and welcoming — a great spot to experience Suzhou''s local snack culture.</p><h3>Lao Chenjia</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 10 Shilin Temple Lane, Gusu District, Suzhou <strong>Phone:</strong> +86 512 6728 8840 <strong>Hours:</strong> Short operating window (confirm in advance) <strong>Average spend:</strong> 60–100 RMB per person (mid-range)</p><h2>Why go:</h2><p>The restaurant sits in a lane flanked by two stone lions — hard to miss. The kitchen presents traditional, honest flavors made from fresh ingredients, and thanks to very reasonable pricing, Lao Chenjia has been a firm local favorite for 30 years. The signature braised pork belly and mock chicken casserole arrives in its cooking pot — the belly is braised until meltingly tender, the mock chicken (pressed tofu roll) soaks up all the savory-sweet pork juices, and the flavor is rich without being cloying. Seating is limited and hours are short, so reservations are a good idea.</p><h3>Weiji Aozao Noodle Restaurant</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Noodles (Aozao-style) <strong>Address:</strong> 266 Baita East Road, Gusu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 25–45 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>Open for over 20 years, the shop is kept clean and tidy — cloud-pattern red lanterns and wooden tables give the space a pleasantly old-fashioned feel. As the name suggests, Aozao noodles are the specialty. Diners can customize broth volume, oil level, and noodle doneness, and choose single or double toppings from classics like braised pork and flash-fried eel — all simple, satisfying, and well-executed. The Aozao fragrant eel noodles are particularly recommended: a rich, sweet red broth with eel cooked until tender through and through, well worth an order.</p><h3>Gejiawu Nongjiale</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Jiangsu (farmhouse cooking) <strong>Address:</strong> Group 17, Gejiawu, Shushan Village, Dashishan Road, Huqiu District, Suzhou <strong>Phone:</strong> +86 137 7612 9359 <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 80–150 RMB per person (mid-range)</p><h2>Why go:</h2><p>Set in Shushan ecological village in Huqiu District, backed by hills and surrounded by greenery. The kitchen has spent more than ten years making traditional Suzhou dishes, and the honest, local flavors have earned a loyal local following. The river clam with black medic shoots is a highlight — only the tender young tips of the plant are used, fragrant and lightly herbal. The Suzhou-style braised goose is slow-cooked in an aged brine of sixteen spices until the meat is soft, fatty, and suffused with fragrance right to the bone. After the meal, a walk to the nearby bamboo forest boardwalk is a fine way to finish. If you''re driving, confirm parking availability in advance.</p><h3>Baisheng Renjia</h3><p><strong>Rating:</strong> Bib Gourmand <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 45 Dongqing Road, Wuzhong District, Suzhou <strong>Phone:</strong> +86 512 6563 0111 <strong>Hours:</strong> Confirm in advance (reservation recommended) <strong>Average spend:</strong> 180–300 RMB per person (mid-to-high end; private rooms only)</p><h2>Why go:</h2><p>Technically accomplished cooking that delivers classic Suzhou flavors without unnecessary fuss, using fresh seasonal ingredients, with rotating specials tied to the time of year. The interior incorporates traditional Chinese design elements; the restaurant serves in private rooms only — book ahead and arrange your menu in advance. The signature crispy eel strips are made to order — golden, crunchy, and sweet-savory, a perfect match with rice. The Suzhou braised pork rice pot combines Northeastern Wuchang rice with glutinous rice for a soft, sticky base that soaks up every drop of pork fat. Deeply satisfying.</p><h2>Michelin Selected Restaurants</h2><h3>Huilaotang Prime Minister''s Residence Private Cuisine</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> Collect at the entrance to Luxiang Ancient Village, Dongshan Town, Wuzhong District, Suzhou <strong>Phone:</strong> +86 512 6628 7971 <strong>Hours:</strong> Confirm in advance (menu must be arranged ahead of time) <strong>Average spend:</strong> 600–800 RMB per person (high-end; menu must be arranged in advance)</p><h2>Why go:</h2><p>This ancient residence was the ancestral home of Wang Ao, Grand Secretary of the Ming dynasty — it carries nearly five hundred years of history, looking out across the poetic scenery of Lake Tai. The menu changes with the seasons: spring vegetables in spring, crab in autumn, every ingredient allowed to be its best. The Dongshan poached mutton is a standout — simply seasoned, it lets the natural fragrance, tenderness, and sweetness of the lamb speak for themselves. The Gusu twin-style shrimp uses Lake Tai white shrimp prepared two ways — lightly stir-fried and quick-wok-fried — each revealing a different dimension of the same ingredient. Menu must be arranged with the restaurant in advance.</p><h3>Lingling Jiujia</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> A white two-storey building approximately 100 metres east of Jiangbei Chang bus stop, Cangbei Road, Wuzhong District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 200–400 RMB per person (mid-to-high end)</p><h2>Why go:</h2><p>Located in a white building in Cangshu Town, the kitchen takes traditional Suzhou cuisine seriously. Produce comes from the restaurant''s own land and neighboring farms, along with fresh lake catches from Lake Tai — only same-day fresh ingredients are used, so many dishes must be reserved in advance. The signature squirrel-shaped mandarin fish is beautifully presented — crispy outside, tender within, with a sweet and sour sauce that complements the delicate fish perfectly. Shrimp roe water bamboo is crisp, fresh, and lightly savory — a must-order at every table. There is no printed menu; ask the server for recommendations.</p><h3>Xinjufeng Caiguan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 2nd Floor, 9 Taijian Lane, Gusu District, Suzhou <strong>Phone:</strong> 0512-65219940 <strong>Hours:</strong> 11:00–13:30, 17:30–20:30 <strong>Average spend:</strong> 80–150 RMB per person (mid-range)</p><h2>Why go:</h2><p>A Suzhou institution, founded in 1904 — one of the city''s oldest Suzhou-style restaurants. The kitchen serves traditional Jiangsu cuisine with a seasonal menu that rotates throughout the year. Signature dishes include lees-sauced pond fish fillet, Suzhou-style braised duck, stir-fried river shrimp, and sizzling eel strips. The lees-sauced fish fillet is silky-fresh with a fragrant Shaoxing lees aroma; the braised duck is fork-tender with a rich, reduced sauce. Conveniently located in the Guanqian Street commercial district — a practical and rewarding choice for classic Suzhou cooking.</p><h3>Tongdexing</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Noodles (Suzhou-style) <strong>Address:</strong> 6 Jiayufang, Renmin Road, Gusu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> 07:00–13:00 (note the hours) <strong>Average spend:</strong> 40–80 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>A noodle stall founded in 1931, relaunched in 2018 and now housed in an elegant grey-brick, grey-tile two-storey building with a welcoming entrance — a world apart from the typical noodle shop. The classic Suzhou-style noodles come with dozens of topping options, most cooked fresh to order. The triple-shrimp noodles are the dish to get: dried shrimp roe clings to firm, springy noodles, with plump shrimp and creamy shrimp fat layered on top, delivering wave after wave of briny sweetness. Featured in the documentary series A Bite of China.</p><h3>Xiu</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu-Zhejiang (Jiangzhe) <strong>Address:</strong> Level 1, InterContinental Hotel, 288 Wangdun Road, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 200–350 RMB per person (high-end)</p><h2>Why go:</h2><p>The interior is adorned with Suzhou embroidery works that echo the restaurant''s name and bring a distinctly Chinese aesthetic to the space. Located within the InterContinental Hotel, the setting is refined and comfortable. The head chef specializes in Jiangzhe cuisine, blending traditional and modern techniques. Signature dishes showcase the elegance of Jiangsu-Zhejiang flavors, alongside hotel-quality dim sum. Well-suited to business dining or special occasions.</p><h3>Acheng Fandian</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 66 Fenghuang Street, Gusu District, Suzhou <strong>Phone:</strong> 0512-65118783 <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 55–100 RMB per person (mid-range)</p><h2>Why go:</h2><p>Set in a period-style building with traditional Suzhou eaves, a bold red entrance, and a model squirrel-shaped mandarin fish mounted outside — it''s easy to spot. The restaurant is known for authentic Suzhou cooking, covering classics like squirrel-shaped mandarin fish, sizzling eel paste, and more. The sweet and sour spare ribs are soft and yielding, with a balanced sauce that keeps you reaching for more. The Suzhou-style cold cuts platter brings together springy tripe slices, tender pork, crisp bamboo shoots, and savory, umami-rich seasoning in a satisfying range of textures. Private rooms require advance booking.</p><h3>Yaba Shengjian</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Dim sum (pan-fried pork buns) <strong>Address:</strong> 12 Wenjia''an, Lindun Road, Gusu District, Suzhou <strong>Phone:</strong> 0512-67208077 <strong>Hours:</strong> 06:00–19:30 <strong>Average spend:</strong> 20–30 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>Three generations of craftsmanship have gone into mastering the heat — the bottom of each bun is fried to a deep golden, shatteringly crisp crust, while the body stays soft and pillowy. A gentle bite breaks through to a rush of savory broth. The signature pork-filled bun is tender and juicy, seasoned with spring onion, ginger, and sesame. The vegetarian version, filled with Indian aster greens and pressed tofu, is clean and fragrant, and the osmanthus sugar taro balls are equally worth trying. The shop runs over two floors; expect queues and communal tables — it''s popular for good reason.</p><h3>Jingcaixuan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Cantonese <strong>Address:</strong> Units B5–B6, Phase 1, Li Gong Di, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 400–600 RMB per person (high-end)</p><h2>Why go:</h2><p>The interior is stylish and comfortable, with large-scale art installations and private rooms that overlook the lake. The menu is primarily Cantonese, with creative touches that nod to Jiangzhe flavors. The braised oxtail casserole in house sauce is a highlight — the oxtail is cooked until it falls apart in silky, deeply flavored strands. The white-cut chicken is aromatic and perfectly balanced in fat, with the distinctive chew of free-range bird. Located on Li Gong Di by Jinji Lake, in a polished setting suited to business dining or family gatherings.</p><h3>Yueshanfang</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Cantonese <strong>Address:</strong> 15th Floor, Fairfield Hotel, 999 Binhe Road, Huqiu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 250–400 RMB per person (high-end)</p><h2>Why go:</h2><p>Beyond the head chef, most of the kitchen team also hails from Guangdong — they know Cantonese cooking deeply and are skilled at weaving creative elements into traditional dishes, interpreting Eastern culinary culture on their own terms. The menu covers roast meats, stir-fries, and seasonal soups. The crispy-skinned glass pigeon has skin that shatters on contact and flesh that is delicate and juicy — served with deep-fried golden ginger threads, it''s a combination that works beautifully, and pre-ordering is recommended. A comfortable dining room and separate private rooms make it suitable for hosting.</p><h3>Banlan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Fujian <strong>Address:</strong> 3rd Floor, Building 8 Podium, Canal Platinum Bay Financial Plaza, 6 Lingyan Street, Huqiu District, Suzhou <strong>Phone:</strong> +86 512 6262 6006 <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 200–350 RMB per person (high-end)</p><h2>Why go:</h2><p>The head chef is from Fujian and uses a generous range of hometown ingredients. The menu includes several well-priced set options alongside seasonal specials. The signature Quanzhou old-ginger duck uses two-to-three-year-old ginger to braise Fujian Muscovy duck until the meat is tender and richly perfumed with ginger; large and small portions are both available. The taro puree bird''s nest peanut soup elevates a traditional peanut soup with smooth taro and delicate bird''s nest, adding a refined touch. The restaurant has both main dining and private rooms, making it easy for group dinners, and Fujian tea is available to accompany the meal.</p><h3>Heshun Mutton Restaurant</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Cangshu mutton) <strong>Address:</strong> 2270 Qiongling Road, Wuzhong District, Suzhou <strong>Phone:</strong> +86 138 1278 7087 <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 60–100 RMB per person (mid-range)</p><h2>Why go:</h2><p>Three floors with private rooms of various sizes and on-site parking — well-suited to larger groups and family-friendly. Reservations are made directly with the restaurant; overseas credit cards are not accepted. The signature roasted lamb leg is firm-textured and coated in cumin, wonderfully aromatic and highly recommended. The house mung bean soup is a point of pride — layered in texture, with a hint of mint that refreshes without overpowering. The overall menu revolves around mutton, covering cold starters, soups, stir-fries, and staples, with set menus at different price points.</p><h3>Wantai Xing</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Noodles (Suzhou-style) <strong>Address:</strong> 670 Shiquan Street, Gusu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 35–70 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>Originally a noodle stall founded in 1931, relaunched in 2018 and now occupying a handsome two-storey grey-brick building with a proper entrance hall — a step above the average noodle shop. Classic Suzhou-style noodles come with dozens of topping options, most cooked fresh to order. The triple-shrimp noodles are outstanding: dried shrimp roe coats springy noodles, with plump shrimp and creamy shrimp fat layered on top, building wave after wave of briny umami. The Fengzhen braised pork noodles are another signature not to miss.</p><h3>Yumiantang</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Noodles (Suzhou-style) <strong>Address:</strong> 73–77 Nanxin Road, Gusu District, Suzhou <strong>Phone:</strong> 0512-68705018 / 180 6843 9777 <strong>Hours:</strong> 08:00–14:00, 17:00–20:00 <strong>Average spend:</strong> 60–90 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>Yumiantang has a long and storied history — it was first established in the second year of the Guangxu Emperor''s reign (1876), closed during wartime, and revived in 2019 by a descendant of the founding family. The dining room is hung with Jiangnan-style lanterns, with canal-town views framed in the windows. Noodles are made from Xinjiang wheat flour, and the broth builds on tradition with dried ingredients for extra depth. In summer the triple-shrimp noodles reign — springy shrimp paired with dried shrimp roe and creamy shrimp fat, intensely savory. In winter, the crab roe noodles take over as the headline dish.</p><h3>Tangyuan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Noodles (Suzhou-style) <strong>Address:</strong> 38 Fangjishang, Shantang Street, Gusu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 40–80 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>Housed in a period-style building full of Jiangnan character, the dining room is comfortable and relaxed. The noodle menu is extensive — red broth, white broth, and dry-tossed options, each with a broad selection of toppings. The signature five-shrimp noodles stack shrimp, dried shrimp roe, shrimp broth, shrimp oil, and shrimp fat into a single bowl, building layers of freshness that unfold with every mouthful. The traditional braised pork hock is firm yet yielding in the skin, with a straightforward depth of flavor that never feels one-note. Set meals combine noodles, a topping, soup, and side dishes — a good way to sample multiple things at once.</p><h3>Gusuqiao</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Noodles (Suzhou-style) <strong>Address:</strong> 12–14 First Tianmen, Guanqian Street, Gusu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 50–90 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>The noodle shop features Jiangnan courtyard-style eaves and classical Chinese calligraphy and paintings inside — the layout has an elegant, unhurried quality. The menu lists nearly fifty hot and cold Suzhou-style toppings, including inventive contemporary options, alongside set meals combining a bowl of noodles with a few house specials. The four-flavor cold platter — braised duck, lamb aspic, candied cashews, and soy-pickled radish — rotates with the seasons and is well worth ordering. During crab season, a bowl of pure crab fat tossed noodles is about as good as it gets.</p><h3>Gusu Loushang</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Cantonese and Jiangsu (fusion) <strong>Address:</strong> 28 Pingqiao Zhi Street, Gusu District, Suzhou <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance (advance reservation required) <strong>Average spend:</strong> 60–120 RMB per person (budget-friendly)</p><h2>Why go:</h2><p>Led by a Cantonese chef, the kitchen blends Suzhou and Cantonese cooking into something distinct. The Jinling old-brine goose uses Lake Tai white goose, slow-braised in a pot of over 30 Chinese herbs and spices until the meat is tender and thoroughly infused with the fragrance of the brine. The golden chrysanthemum fish shapes mandarin fish into a striking flower form, fried until crispy outside and tender within without losing any freshness, then finished with a house sauce — sweet, sour, and appetite-opening. In addition to the main dining room, there are private rooms in a more refined setting; advance reservation is required for all dining.</p><h3>Yueshi Dongfang</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Chaozhou (Teochew) <strong>Address:</strong> Unit 03-27/62, 3rd Floor, South Zone, Suzhou Centre, Xinggang Street, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 200–350 RMB per person (mid-to-high end)</p><h2>Why go:</h2><p>The cooking bridges tradition and modern sensibility to present Chaozhou cuisine with a distinct voice. An open kitchen and live seafood tanks are on display; seafood is flown in daily from Guangdong. The zucchini soup with Chaozhou double meatballs is beautifully balanced — the clean sweetness of the zucchini plays against the springy fish balls and beef balls. The olive kernel sachima is the dessert to order: egg-rich, light, and delicately soft. The restaurant is busy, so reservations are strongly advised.</p><h3>Jinjingge</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu-Zhejiang (Jiangzhe) <strong>Address:</strong> Level 1, Four Seasons Hotel, 88 Siji Road, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 500–900 RMB per person (high-end; tasting menu 888 RMB per person)</p><h2>Why go:</h2><p>The dining room is elegant and luxurious, with floor-to-ceiling windows overlooking the hotel''s inner garden pond. The head chef is from Shanghai and brings years of experience at acclaimed Jiangzhe restaurants in Hangzhou. He draws on Shaoxing''s distinctive dried preserved vegetables and finds inspiration in The Suiyuan Menu — the classic 18th-century culinary text — to revive historical dishes according to the season. The menu spans both traditional Jiangzhe recipes and refined Jiangsu interpretations. The handmade dim sum at lunch is particularly worth seeking out.</p><h3>Banting Jiayan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> Level 1, Tonino Lamborghini Hotel, 168 Xinggang Street, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 500–800 RMB per person (high-end)</p><h2>Why go:</h2><p>The restaurant overlooks Jinji Lake, and a small stage hosts nightly performances of pingtan or kunqu opera — dining here means eating well and absorbing Suzhou culture at the same time. The shrimp-roe crispy-scaled white fish is a showpiece: fresh local white fish with delicately tender flesh, the scales fried to a crisp, served on a platter nearly a metre long — dramatic and perfect for sharing. The traditional Suzhou sweet congee with fox nuts is smooth, sweet, and comforting; the square rice cakes carry the warm fragrance of red dates and nuts — both are memorable Suzhou sweets.</p><h3>Sumianfang</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Noodles (Suzhou-style) <strong>Address:</strong> Level 1, Tonino Lamborghini Hotel, 168 Xinggang Street, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 30–80 RMB per person (budget-friendly; noodles from 18 RMB)</p><h2>Why go:</h2><p>Sumianfang''s roots go back to the 1930s and 1940s. Descendants of the founders have recently given the brand a thoughtful upgrade, presenting Suzhou noodles in a more refined environment and with more polished execution. The restaurant faces the lake, and the interiors carry a classical elegance. The menu ranges from local-flavor dim sum and side dishes to traditional Suzhou-style noodles with seasonal toppings. During crab season, order the pure crab fat noodles — the rich, fragrant oils of crab roe and crab fat seal in an intensity of flavor that lingers long after the bowl is empty.</p><h3>Xizhouxuan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Huaiyang) <strong>Address:</strong> Level 1, Park Hyatt Hotel, 69 Xizhou Road, Suzhou Industrial Park <strong>Phone:</strong> +86 512 8666 1234 <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 400–500 RMB per person (high-end)</p><h2>Why go:</h2><p>The interior draws inspiration from Suzhou classical gardens, with a serene central water feature, and decorative elements throughout referencing local culture — lattice windows, panel paintings. The head chef is from Yangzhou; the menu covers Huaiyang cuisine, Suzhou specialties, and a roasted duck series. The original house soup "Picking Lotus in the Southern Pond" stuffs minced chicken with sweet peas shaped into lotus pods, and binds bamboo pith mushroom with hair moss to resemble small lotus roots — a composition that evokes the beauty of a summer pond. The handmade square rice cakes and goose-fat sesame pastries are also worth trying.</p><h3>Xiyuan</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Huaiyang) <strong>Address:</strong> 2nd Floor, Suzhou Shangri-La Hotel, Xie Xin Plaza, 99 Si''an Street, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 150–250 RMB per person (mid-to-high end)</p><h2>Why go:</h2><p>The decor is richly classical — screens and walnut-toned furniture underscore the Chinese aesthetic, while pink tablecloths add a note of lightness. The menu is anchored in Huaiyang cuisine, with salt-water duck, Wensi tofu soup, and other iconic dishes all present. The head chef also incorporates Suzhou flavors to give the cooking a local dimension. The Suzhou-style smoked fish is crispy outside and tender within, with a sauce that balances sweet, salty, and savory in layers that linger. The Huaiyang "soft pocket" eel is glossy and dark, the flesh firm and springy, perfumed with garlic and white pepper.</p><h3>Huachi 88</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangsu (Suzhou-style) <strong>Address:</strong> 2nd Floor, Hyatt Regency Hotel, 88 Huachi Street, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 300–400 RMB per person (mid-to-high end)</p><h2>Why go:</h2><p>The head chef has worked in kitchens for over 30 years, specializing in Jiangsu cuisine and prioritizing local, fresh ingredients. The signature Jiangnan-style drunken braised beef is meltingly soft, coated in a gently sweet sauce that never becomes cloying. The house-made Suzhou pine cake is soft, lightly sweet, and a genuine local specialty. In addition to a la carte, custom menus can be arranged in advance for a more nostalgic, handcrafted dining experience. An open kitchen sits at the center of the dining room, so you can watch the cooking unfold.</p><h3>Zhuoyan and Zhumian</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Jiangzhe and Cantonese (fusion) <strong>Address:</strong> Building 19, Phase 4, Li Gong Di, Suzhou Industrial Park <strong>Phone:</strong> +86 512 6615 3588 <strong>Hours:</strong> Lunch serves Suzhou-style noodles only; dinner is by reservation <strong>Average spend:</strong> 150–350 RMB per person (lunch noodles 40–80 RMB; dinner 300–500 RMB)</p><h2>Why go:</h2><p>The restaurant takes its name from the Humble Administrator''s Garden, and the owner aims to convey the essence of Suzhou culture through the interiors and the food. At lunch, only Suzhou-style noodles are served — the red broth version stands out, built on a base of pork bones and chicken for a full-bodied, rounded flavor. Dinner offers a reservation-only fusion tasting experience framed around Jiangzhe cuisine and Suzhou local flavors. The head chef''s crispy-skinned young pigeon — the skin is impossibly thin and shatters at the touch, the meat fresh and juicy — is the dish to order.</p><h3>Yueshi Dongfang (Wangdun Road)</h3><p><strong>Rating:</strong> Michelin Selected <strong>Cuisine:</strong> Chaozhou (Teochew) <strong>Address:</strong> 27th Floor, InterContinental Hotel, 288 Wangdun Road, Suzhou Industrial Park <strong>Phone:</strong> Confirm in advance <strong>Hours:</strong> Confirm in advance <strong>Average spend:</strong> 500–700 RMB per person (high-end)</p><h2>Why go:</h2><p>The head chef is a native of Chaozhou, with a thorough command of his hometown''s ingredients and an unwavering commitment to traditional cooking methods. Signature dishes include salt-preserved lemon duck broth and other distinctly Teochew preparations. Perched on the 27th floor of the InterContinental Hotel, the restaurant offers commanding views across Suzhou Industrial Park. The menu blends traditional and contemporary Chaozhou flavors. Brine-braised cold cuts and Chaozhou congee are among the recommended dishes. Well-suited to business dining or special occasions.</p>',
